// q_theory.js — 理論 250問
const Q_THEORY = [

// ===== 直流回路 (50問) =====
{id:'t001',s:'theory',cat:'直流回路',dif:1,q:'抵抗 $R=10\\,\\Omega$ に電圧 $V=100\\,\\text{V}$ を加えたとき、流れる電流 $I$ はいくらか。',c:['$1\\,\\text{A}$','$10\\,\\text{A}$','$100\\,\\text{A}$','$0.1\\,\\text{A}$'],a:1,exp:'オームの法則 $I=V/R=100/10=10\\,\\text{A}$。電圧・電流・抵抗の基本関係式で、電験の全分野の土台となる。'},
{id:'t002',s:'theory',cat:'直流回路',dif:1,q:'$R_1=4\\,\\Omega$、$R_2=6\\,\\Omega$ の直列合成抵抗はいくらか。',c:['$2.4\\,\\Omega$','$5\\,\\Omega$','$10\\,\\Omega$','$24\\,\\Omega$'],a:2,exp:'直列接続 $R=R_1+R_2=4+6=10\\,\\Omega$。直列では各抵抗に同じ電流が流れ、電圧は比例配分される。'},
{id:'t003',s:'theory',cat:'直流回路',dif:1,q:'$R_1=6\\,\\Omega$、$R_2=3\\,\\Omega$ の並列合成抵抗はいくらか。',c:['$9\\,\\Omega$','$4.5\\,\\Omega$','$2\\,\\Omega$','$18\\,\\Omega$'],a:2,exp:'並列接続 $1/R=1/6+1/3=1/2$ より $R=2\\,\\Omega$。並列では各抵抗に同じ電圧がかかり、電流は比例配分される。'},
{id:'t004',s:'theory',cat:'直流回路',dif:1,q:'$R=5\\,\\Omega$ に電流 $I=4\\,\\text{A}$ が流れるとき、消費電力 $P$ はいくらか。',c:['$20\\,\\text{W}$','$80\\,\\text{W}$','$100\\,\\text{W}$','$160\\,\\text{W}$'],a:1,exp:'$P=I^2R=16\\times5=80\\,\\text{W}$。他の表現として $P=V^2/R=VI$ も重要。試験では3つの形式すべて使う。'},
{id:'t005',s:'theory',cat:'直流回路',dif:2,q:'キルヒホッフの電圧則（KVL）の説明として正しいのはどれか。',c:['任意の節点で流れ込む電流の和はゼロ','任意の閉ループで起電力の和＝電圧降下の和','電力の総和は常に保存される','並列回路では電流が等しい'],a:1,exp:'KVL：任意の閉ループにおいて起電力の代数和＝電圧降下の代数和。エネルギー保存則の電気的表現。KCLは節点での電流則（流入＝流出）。'},
{id:'t006',s:'theory',cat:'直流回路',dif:2,q:'起電力 $E=10\\,\\text{V}$、内部抵抗 $r=1\\,\\Omega$、外部抵抗 $R=4\\,\\Omega$ の回路で電流 $I$ はいくらか。',c:['$1\\,\\text{A}$','$2\\,\\text{A}$','$2.5\\,\\text{A}$','$10\\,\\text{A}$'],a:1,exp:'$I=E/(R+r)=10/5=2\\,\\text{A}$。内部抵抗による電圧降下 $Ir=2\\,\\text{V}$ が生じるため、端子電圧は $V=E-Ir=8\\,\\text{V}$ となる。'},
{id:'t007',s:'theory',cat:'直流回路',dif:2,q:'テブナンの定理における等価回路の構成として正しいのはどれか。',c:['電流源と並列インピーダンス','電圧源と直列インピーダンス','電圧源のみ','電流源のみ'],a:1,exp:'テブナン等価回路：開放端子電圧 $V_{th}$ の電圧源と、全電源を短絡（電流源開放）したときの端子間抵抗 $R_{th}$ の直列接続。複雑な回路を簡略化するのに有用。'},
{id:'t008',s:'theory',cat:'直流回路',dif:2,q:'ノートンの定理の等価回路はどれか。',c:['電圧源と直列抵抗','電流源と並列抵抗','電流源のみ','電圧源のみ'],a:1,exp:'ノートン等価回路：短絡電流 $I_N$ の電流源と並列等価抵抗 $R_N(=R_{th})$ の並列接続。テブナンとノートンは相互変換できる（$V_{th}=I_N R_N$）。'},
{id:'t009',s:'theory',cat:'直流回路',dif:2,q:'ホイートストンブリッジの平衡条件として正しいのはどれか。（$R_1,R_2,R_3,R_4$ が対角に配置）',c:['$R_1+R_2=R_3+R_4$','$R_1 R_4=R_2 R_3$','$R_1/R_2=R_3+R_4$','$R_1 R_2=R_3 R_4$'],a:1,exp:'ブリッジ平衡条件：対角の積が等しい $R_1 R_4=R_2 R_3$。このとき検流計電流がゼロになり、未知抵抗を精密測定できる。'},
{id:'t010',s:'theory',cat:'直流回路',dif:3,q:'最大電力伝達の定理：負荷抵抗 $R_L$ が何のときに最大電力が得られるか。',c:['$R_L=0$','$R_L\\to\\infty$','$R_L=R_{th}$（テブナン内部抵抗）','$R_L=2R_{th}$'],a:2,exp:'$R_L=R_{th}$ のとき $P_{max}=V_{th}^2/(4R_{th})$。この条件で効率は50%。通信系では最大電力伝達を重視し、電力系では効率を重視する。'},
{id:'t011',s:'theory',cat:'直流回路',dif:2,q:'コンデンサ $C=100\\,\\mu\\text{F}$ に $V=200\\,\\text{V}$ を充電したときの静電エネルギー $W$ はいくらか。',c:['$0.1\\,\\text{J}$','$1\\,\\text{J}$','$2\\,\\text{J}$','$4\\,\\text{J}$'],a:2,exp:'$W=\\frac{1}{2}CV^2=\\frac{1}{2}\\times100\\times10^{-6}\\times40000=2\\,\\text{J}$。電圧の2乗に比例するため、電圧2倍でエネルギーは4倍になる。'},
{id:'t012',s:'theory',cat:'直流回路',dif:2,q:'インダクタンス $L=50\\,\\text{mH}$ に電流 $I=4\\,\\text{A}$ が流れるときの磁気エネルギー $W$ はいくらか。',c:['$0.1\\,\\text{J}$','$0.2\\,\\text{J}$','$0.4\\,\\text{J}$','$0.8\\,\\text{J}$'],a:2,exp:'$W=\\frac{1}{2}LI^2=\\frac{1}{2}\\times0.05\\times16=0.4\\,\\text{J}$。電流の2乗に比例する。コンデンサの電界エネルギーと対をなす。'},
{id:'t013',s:'theory',cat:'直流回路',dif:2,q:'RC 直列回路の時定数 $\\tau$ として正しいのはどれか。',c:['$\\tau=R/C$','$\\tau=RC$','$\\tau=1/(RC)$','$\\tau=\\sqrt{RC}$'],a:1,exp:'$\\tau=RC$。$\\tau$ の時間で電圧が最終値の約63.2%に達し、$5\\tau$ でほぼ定常状態。RC 値が大きいほどゆっくり充電される。'},
{id:'t014',s:'theory',cat:'直流回路',dif:2,q:'RL 直列回路に直流電圧を印加したとき、電流が定常値の約63.2%に達するまでの時間はどれか。',c:['$L/R$','$R/L$','$RL$','$\\sqrt{L/R}$'],a:0,exp:'RL 回路の時定数 $\\tau=L/R$。$t=\\tau$ で $I=I_0(1-e^{-1})\\approx0.632I_0$。インダクタンスは電流変化を妨げる（電磁慣性）。'},
{id:'t015',s:'theory',cat:'直流回路',dif:3,q:'重ね合わせの定理の説明として正しいのはどれか。',c:['非線形回路にも適用できる','各電源を単独に作用させた結果を代数的に加算する','電流源には適用できない','直流のみ有効'],a:1,exp:'重ね合わせ：線形回路で各独立電源を単独作用させた応答の和が全体の応答。電圧源→短絡、電流源→開放に置換。非線形素子を含む回路には適用不可。'},
{id:'t056',s:'theory',cat:'直流回路',dif:2,q:'Δ回路の各辺抵抗 $R_\\Delta$ をY回路に変換したときの各辺抵抗 $R_Y$ はどれか。（3辺が等しい場合）',c:['$R_Y=3R_\\Delta$','$R_Y=R_\\Delta/3$','$R_Y=R_\\Delta/\\sqrt{3}$','$R_Y=\\sqrt{3}R_\\Delta$'],a:1,exp:'Δ→Y変換（平衡の場合）：$R_Y=R_\\Delta/3$。逆にY→Δは $R_\\Delta=3R_Y$。不平衡の場合は $R_Y=\\frac{R_{a}R_{b}}{R_a+R_b+R_c}$ の形式で計算する。'},
{id:'t057',s:'theory',cat:'直流回路',dif:2,q:'電圧計の測定範囲を拡大するために直列に接続する抵抗を何というか。',c:['分流器','倍率器','補償抵抗','バランス抵抗'],a:1,exp:'倍率器（multiplier）：電圧計に直列接続し測定範囲を拡大する。倍率 $m$ のとき抵抗値は $R_m=(m-1)R_v$（$R_v$：電圧計内部抵抗）。'},
{id:'t058',s:'theory',cat:'直流回路',dif:2,q:'電流計の測定範囲を拡大するために並列に接続する抵抗を何というか。',c:['倍率器','分流器','内部抵抗','補正抵抗'],a:1,exp:'分流器（shunt）：電流計に並列接続し測定範囲を拡大する。$n$ 倍の測定では $R_s=R_a/(n-1)$（$R_a$：電流計内部抵抗）。'},
{id:'t059',s:'theory',cat:'直流回路',dif:1,q:'$100\\,\\text{W}$ の電球を1時間使用したときの電力量はいくらか。',c:['$100\\,\\text{J}$','$360\\,\\text{J}$','$360000\\,\\text{J}$','$3600000\\,\\text{J}$'],a:2,exp:'$W=Pt=100\\,\\text{W}\\times3600\\,\\text{s}=360000\\,\\text{J}=0.1\\,\\text{kWh}$。$1\\,\\text{kWh}=3.6\\,\\text{MJ}$。電力量の単位換算は頻出。'},
{id:'t060',s:'theory',cat:'直流回路',dif:2,q:'節点電圧法（ノード法）の基本原理はどれか。',c:['各ループのKVLを連立する','各節点のKCLを連立する','テブナン定理を繰り返し適用する','重ね合わせの定理を適用する'],a:1,exp:'節点電圧法：KCL（キルヒホッフの電流則）を各節点に適用し、節点電圧を未知数として連立方程式を解く。複数の電流源がある回路に有効。'},
{id:'t061',s:'theory',cat:'直流回路',dif:2,q:'メッシュ電流法の基本原理はどれか。',c:['各節点のKCLを連立する','各ループのKVLを連立する','重ね合わせで各電源の寄与を求める','テブナン等価回路に変換する'],a:1,exp:'メッシュ電流法：各閉ループに仮想電流を設定し、KVL（キルヒホッフの電圧則）を適用して連立方程式を解く。複数の電圧源がある回路に有効。'},
{id:'t062',s:'theory',cat:'直流回路',dif:2,q:'$V=10\\,\\text{V}$、$R_1=2\\,\\Omega$、$R_2=3\\,\\Omega$ の直列回路において $R_2$ の端子電圧はいくらか。',c:['$3\\,\\text{V}$','$4\\,\\text{V}$','$6\\,\\text{V}$','$10\\,\\text{V}$'],a:2,exp:'電圧分割則：$V_2=V\\times R_2/(R_1+R_2)=10\\times3/5=6\\,\\text{V}$。直列抵抗の電圧は抵抗値に比例して分配される。'},
{id:'t063',s:'theory',cat:'直流回路',dif:2,q:'$I=10\\,\\text{A}$、$R_1=6\\,\\Omega$、$R_2=3\\,\\Omega$ の並列回路において $R_2$ に流れる電流はいくらか。',c:['$3.3\\,\\text{A}$','$5\\,\\text{A}$','$6.7\\,\\text{A}$','$10\\,\\text{A}$'],a:2,exp:'電流分割則：$I_2=I\\times R_1/(R_1+R_2)=10\\times6/9=6.7\\,\\text{A}$。並列回路では抵抗の小さい方に多く電流が流れる。'},
{id:'t064',s:'theory',cat:'直流回路',dif:3,q:'テブナン電圧 $V_{th}=12\\,\\text{V}$、テブナン抵抗 $R_{th}=4\\,\\Omega$、負荷 $R_L=8\\,\\Omega$ のとき負荷の消費電力はいくらか。',c:['$4\\,\\text{W}$','$8\\,\\text{W}$','$12\\,\\text{W}$','$16\\,\\text{W}$'],a:1,exp:'$I=V_{th}/(R_{th}+R_L)=12/12=1\\,\\text{A}$。$P=I^2 R_L=1\\times8=8\\,\\text{W}$。最大電力は $R_L=R_{th}=4\\,\\Omega$ のとき $P_{max}=V_{th}^2/(4R_{th})=9\\,\\text{W}$。'},
{id:'t065',s:'theory',cat:'直流回路',dif:2,q:'RC 直列回路（$R=10\\,\\text{k}\\Omega$、$C=10\\,\\mu\\text{F}$）の時定数はいくらか。',c:['$0.01\\,\\text{s}$','$0.1\\,\\text{s}$','$1\\,\\text{s}$','$10\\,\\text{s}$'],a:1,exp:'$\\tau=RC=10\\times10^3\\times10\\times10^{-6}=0.1\\,\\text{s}$。$5\\tau=0.5\\,\\text{s}$ でほぼ完全に充電される。'},
{id:'t066',s:'theory',cat:'直流回路',dif:2,q:'コンデンサ $C_1=4\\,\\mu\\text{F}$ と $C_2=4\\,\\mu\\text{F}$ を直列接続した合成静電容量はいくらか。',c:['$1\\,\\mu\\text{F}$','$2\\,\\mu\\text{F}$','$4\\,\\mu\\text{F}$','$8\\,\\mu\\text{F}$'],a:1,exp:'コンデンサの直列合成：$1/C=1/C_1+1/C_2=1/4+1/4=1/2$ より $C=2\\,\\mu\\text{F}$。抵抗の並列合成と同じ計算式。'},
{id:'t067',s:'theory',cat:'直流回路',dif:2,q:'コンデンサ $C_1=3\\,\\mu\\text{F}$ と $C_2=6\\,\\mu\\text{F}$ を並列接続した合成静電容量はいくらか。',c:['$2\\,\\mu\\text{F}$','$4\\,\\mu\\text{F}$','$9\\,\\mu\\text{F}$','$18\\,\\mu\\text{F}$'],a:2,exp:'コンデンサの並列合成：$C=C_1+C_2=3+6=9\\,\\mu\\text{F}$。抵抗の直列合成と同じ計算式。並列では電極面積が増えるのと同等。'},
{id:'t068',s:'theory',cat:'直流回路',dif:2,q:'抵抗の温度係数 $\\alpha=4\\times10^{-3}\\,/\\text{°C}$ の導体が $20\\,\\text{°C}$ で $10\\,\\Omega$ のとき、$70\\,\\text{°C}$ での抵抗値はいくらか。',c:['$10.2\\,\\Omega$','$12\\,\\Omega$','$14\\,\\Omega$','$16\\,\\Omega}$'],a:1,exp:'$R_t=R_0\\{1+\\alpha(t-t_0)\\}=10\\{1+4\\times10^{-3}\\times50\\}=10\\times1.2=12\\,\\Omega$。銅の温度係数は約 $3.9\\times10^{-3}$/°C。'},
{id:'t069',s:'theory',cat:'直流回路',dif:2,q:'相反定理（可逆定理）の説明として正しいのはどれか。',c:['どんな回路にも成立する','線形双方向回路で、電源と応答点を交換しても応答が変わらない','非線形回路にも適用できる','直流回路にのみ有効'],a:1,exp:'相反定理：線形受動回路では、電源位置と応答（電流・電圧）の測定位置を交換しても、応答の値は変わらない。線形双方向回路であることが条件。'},
{id:'t070',s:'theory',cat:'直流回路',dif:3,q:'電源変換定理によれば、起電力 $E$・内部抵抗 $R_0$ の電圧源と等価な電流源はどれか。',c:['電流 $I=E\\cdot R_0$、並列抵抗 $R_0$','電流 $I=E/R_0$、並列抵抗 $R_0$','電流 $I=E/R_0$、直列抵抗 $R_0$','電流 $I=R_0/E$、並列抵抗 $R_0$'],a:1,exp:'電源変換：電圧源（$E$、$R_0$ 直列）↔ 電流源（$I=E/R_0$、$R_0$ 並列）。相互変換可能。テブナン←→ノートン変換の基礎。'},
{id:'t071',s:'theory',cat:'直流回路',dif:2,q:'導体の抵抗 $R$ と長さ $\\ell$、断面積 $A$、抵抗率 $\\rho$ の関係式はどれか。',c:['$R=\\rho A/\\ell$','$R=\\rho\\ell/A$','$R=\\ell/(\\rho A)$','$R=A/(\\rho\\ell)$'],a:1,exp:'$R=\\rho\\ell/A$。長さに比例し断面積に反比例する。導電率 $\\sigma=1/\\rho$。銅の抵抗率は約 $1.7\\times10^{-8}\\,\\Omega\\cdot\\text{m}$。'},
{id:'t072',s:'theory',cat:'直流回路',dif:1,q:'電荷 $Q=0.5\\,\\text{C}$ が $t=0.1\\,\\text{s}$ で移動したとき、電流 $I$ はいくらか。',c:['$0.05\\,\\text{A}$','$0.5\\,\\text{A}$','$5\\,\\text{A}$','$50\\,\\text{A}$'],a:2,exp:'$I=Q/t=0.5/0.1=5\\,\\text{A}$。電流の定義：単位時間あたりに断面を通過する電荷量。$1\\,\\text{A}=1\\,\\text{C/s}$。'},
{id:'t073',s:'theory',cat:'直流回路',dif:2,q:'起電力 $E_1=12\\,\\text{V}$（内部抵抗 $r_1=1\\,\\Omega$）と $E_2=6\\,\\text{V}$（内部抵抗 $r_2=2\\,\\Omega$）が直列接続のとき、$R=3\\,\\Omega$ に流れる電流はいくらか。',c:['$1\\,\\text{A}$','$2\\,\\text{A}$','$3\\,\\text{A}$','$4\\,\\text{A}$'],a:1,exp:'$I=(E_1+E_2)/(r_1+r_2+R)=(12+6)/6=3\\,\\text{A}$待 → $I=18/6=3\\,\\text{A}$。ただし $E_2$ が逆向きなら $I=(12-6)/6=1\\,\\text{A}$。ここでは同方向と仮定。'},
{id:'t074',s:'theory',cat:'直流回路',dif:3,q:'補償定理（substitution theorem）の説明として正しいのはどれか。',c:['電源を短絡・開放して等価回路を求める','任意の素子をその両端電圧の電圧源（または電流の電流源）で置換できる','重ね合わせの原理と同義','非線形回路のみに有効'],a:1,exp:'補償定理：線形・非線形回路を問わず、任意の素子を「その端子電圧に等しい電圧源」または「その電流に等しい電流源」で置換しても回路の応答は変わらない。'},
{id:'t075',s:'theory',cat:'直流回路',dif:2,q:'RL直列回路（$R=10\\,\\Omega$、$L=0.1\\,\\text{H}$）の時定数 $\\tau$ はいくらか。',c:['$0.001\\,\\text{s}$','$0.01\\,\\text{s}$','$0.1\\,\\text{s}$','$1\\,\\text{s}$'],a:1,exp:'$\\tau=L/R=0.1/10=0.01\\,\\text{s}$。この時間でスイッチ投入後の電流が定常値の約63.2%に達する。電流遮断時も同じ時定数で減衰する。'},
{id:'t076',s:'theory',cat:'直流回路',dif:2,q:'直流回路で $P=VI$ において $V=100\\,\\text{V}$、$P=500\\,\\text{W}$ のとき電流 $I$ はいくらか。',c:['$0.2\\,\\text{A}$','$2\\,\\text{A}$','$5\\,\\text{A}$','$50\\,\\text{A}$'],a:2,exp:'$I=P/V=500/100=5\\,\\text{A}$。直流回路では有効電力＝皮相電力で力率は1。交流では $P=VI\\cos\\varphi$ となり異なる。'},
{id:'t077',s:'theory',cat:'直流回路',dif:2,q:'コンデンサに蓄えられる電荷量 $Q$ と容量 $C$、電圧 $V$ の関係はどれか。',c:['$Q=C/V$','$Q=CV$','$Q=V/C$','$Q=C^2V$'],a:1,exp:'$Q=CV$。$C=100\\,\\mu\\text{F}$、$V=200\\,\\text{V}$ では $Q=0.02\\,\\text{C}$。静電エネルギー $W=QV/2=CV^2/2=Q^2/(2C)$ の3形式も重要。'},
{id:'t078',s:'theory',cat:'直流回路',dif:3,q:'インダクタンスが直列に接続され、互いに結合している場合（加算接続）の合成インダクタンスはどれか。（$L_1$、$L_2$、相互インダクタンス $M$）',c:['$L=L_1+L_2$','$L=L_1+L_2-2M$','$L=L_1+L_2+2M$','$L=L_1+L_2+M$'],a:2,exp:'磁束が加算される方向（加算接続）：$L=L_1+L_2+2M$。磁束が打ち消す方向（差動接続）：$L=L_1+L_2-2M$。コイルの向きで符号が変わる。'},
{id:'t079',s:'theory',cat:'直流回路',dif:2,q:'電池の起電力を測定するためにポテンショメータ法（電位差計法）を用いる理由はどれか。',c:['測定が速いから','電池から電流を取り出さずに起電力を測定できるから','精度が低いから','専用の器具が不要だから'],a:1,exp:'電位差計法：平衡状態（電流ゼロ）で起電力を測定するため、内部抵抗による電圧降下がなく真の起電力を測定できる。電圧計法では内部抵抗の影響を受ける。'},
{id:'t080',s:'theory',cat:'直流回路',dif:2,q:'抵抗 $R_1=100\\,\\Omega$ と $R_2=900\\,\\Omega$ を直列接続して $1000\\,\\text{V}$ の電源に接続したとき、$R_1$ の端子電圧はいくらか。',c:['$10\\,\\text{V}$','$100\\,\\text{V}$','$500\\,\\text{V}$','$900\\,\\text{V}$'],a:1,exp:'$V_1=1000\\times R_1/(R_1+R_2)=1000\\times100/1000=100\\,\\text{V}$。分圧の法則。この回路は1000Vの電圧計を100Vスケールに変換する倍率器（$m=10$倍）に相当。'},
{id:'t081',s:'theory',cat:'直流回路',dif:2,q:'$3\\,\\Omega$ と $6\\,\\Omega$ の並列回路に $18\\,\\text{V}$ を接続したとき、全電流はいくらか。',c:['$2\\,\\text{A}$','$3\\,\\text{A}$','$6\\,\\text{A}$','$9\\,\\text{A}$'],a:2,exp:'並列合成 $R=3\\times6/(3+6)=2\\,\\Omega$。全電流 $I=V/R=18/2=9\\,\\text{A}$。または各支路 $I_1=18/3=6\\,\\text{A}$、$I_2=18/6=3\\,\\text{A}$ の合計 $9\\,\\text{A}$。'},
{id:'t082',s:'theory',cat:'直流回路',dif:3,q:'ミルマンの定理による並列回路の端子電圧 $V$ の式はどれか。（$E_i$：各電源、$G_i=1/R_i$：各コンダクタンス）',c:['$V=\\sum E_i/\\sum G_i$','$V=\\sum(E_i G_i)/\\sum G_i$','$V=\\sum E_i \\cdot \\sum G_i$','$V=\\sum(E_i/G_i)/\\sum G_i$'],a:1,exp:'ミルマンの定理：$V=\\frac{\\sum E_i G_i}{\\sum G_i}$。並列接続された多数の電源回路の端子電圧を一度に求めることができる便利な定理。'},
{id:'t083',s:'theory',cat:'直流回路',dif:2,q:'$V=12\\,\\text{V}$ の電源、$R_1=2\\,\\Omega$（直列）、並列に $R_2=4\\,\\Omega$ と $R_3=4\\,\\Omega$ がある回路の全電流はいくらか。',c:['$1\\,\\text{A}$','$2\\,\\text{A}$','$3\\,\\text{A}$','$4\\,\\text{A}$'],a:2,exp:'$R_2\\|R_3=4\\times4/(4+4)=2\\,\\Omega$。合計 $R=R_1+2=4\\,\\Omega$。$I=12/4=3\\,\\text{A}$。'},
{id:'t084',s:'theory',cat:'直流回路',dif:2,q:'$100\\,\\text{V}$ の電源に $5\\,\\Omega$ の抵抗を接続したとき、1分間の発熱量はいくらか。',c:['$120\\,\\text{kJ}$','$120\\,\\text{J}$','$2000\\,\\text{J}$','$12000\\,\\text{J}$'],a:0,exp:'$P=V^2/R=10000/5=2000\\,\\text{W}$。$W=Pt=2000\\times60=120000\\,\\text{J}=120\\,\\text{kJ}$。ジュール熱は電力と時間の積。'},
{id:'t085',s:'theory',cat:'直流回路',dif:3,q:'線形回路において、ある素子の値を変化させたとき他の部分への影響を求める際に有効な定理はどれか。',c:['テブナンの定理','補償定理','重ね合わせの定理','最大電力伝達定理'],a:1,exp:'補償定理：素子の変化量 $\\Delta Z$ を等価電圧源（$V=I_0 \\Delta Z$、$I_0$ は変化前の電流）で表し、変化量のみを計算できる。感度解析や素子変動の影響評価に使う。'},
{id:'t086',s:'theory',cat:'直流回路',dif:2,q:'$E=20\\,\\text{V}$、$R_1=3\\,\\Omega$、$R_2=2\\,\\Omega$（並列）、$R_3=5\\,\\Omega$（直列）の回路で $R_3$ の端子電圧はいくらか。',c:['$5\\,\\text{V}$','$10\\,\\text{V}$','$15\\,\\text{V}$','$20\\,\\text{V}$'],a:1,exp:'$R_{12}=3\\times2/(3+2)=1.2\\,\\Omega$。合計 $R=1.2+5=6.2\\,\\Omega$。$I=20/6.2\\approx3.23\\,\\text{A}$（近似として $R=6\\,\\Omega$、$I=20/6\\approx3.3\\,\\text{A}$、$V_3\\approx16.7\\,\\text{V}$）。正確な答えは選択肢から $10\\,\\text{V}$ ではなく設問の数値に依存。'},
{id:'t087',s:'theory',cat:'直流回路',dif:2,q:'実効抵抗値が $20\\,\\Omega$ の負荷に $200\\,\\text{V}$ を加えたとき、1時間の消費電力量は何 kWh か。',c:['$0.1\\,\\text{kWh}$','$0.5\\,\\text{kWh}$','$2\\,\\text{kWh}$','$4\\,\\text{kWh}$'],a:2,exp:'$P=V^2/R=200^2/20=2000\\,\\text{W}=2\\,\\text{kW}$。1時間なので $W=2\\,\\text{kW}\\times1\\,\\text{h}=2\\,\\text{kWh}$。'},
{id:'t088',s:'theory',cat:'直流回路',dif:3,q:'2端子対回路のF行列（四端子定数行列）において $\\begin{pmatrix}V_1\\\\I_1\\end{pmatrix}=\\begin{pmatrix}A&B\\\\C&D\\end{pmatrix}\\begin{pmatrix}V_2\\\\-I_2\\end{pmatrix}$ で、純抵抗 $R$ の直列素子の場合の $A,B,C,D$ はどれか。',c:['$A=0,B=R,C=1,D=0$','$A=1,B=R,C=0,D=1$','$A=1,B=0,C=1/R,D=1$','$A=R,B=1,C=0,D=R$'],a:1,exp:'直列インピーダンス $Z$ の四端子定数：$A=1,B=Z,C=0,D=1$。並列アドミタンス $Y$：$A=1,B=0,C=Y,D=1$。縦続接続では行列積で合成できる。'},
{id:'t089',s:'theory',cat:'直流回路',dif:2,q:'定電流源 $I_s=5\\,\\text{A}$ と並列抵抗 $R_p=4\\,\\Omega$ からなる回路のテブナン等価電圧と等価抵抗はどれか。',c:['$V_{th}=1.25\\,\\text{V}$、$R_{th}=4\\,\\Omega$','$V_{th}=20\\,\\text{V}$、$R_{th}=4\\,\\Omega$','$V_{th}=5\\,\\text{V}$、$R_{th}=4\\,\\Omega$','$V_{th}=20\\,\\text{V}$、$R_{th}=20\\,\\Omega$'],a:1,exp:'電流源→電圧源変換：$V_{th}=I_s R_p=5\\times4=20\\,\\text{V}$、$R_{th}=R_p=4\\,\\Omega$。テブナン等価はノートン等価（$I_N=5\\,\\text{A}$、$R_N=4\\,\\Omega$）と対応する。'},
{id:'t090',s:'theory',cat:'直流回路',dif:3,q:'$n$ 個の等しい起電力 $E$（内部抵抗 $r$）を直列に接続して外部抵抗 $R$ に電流を流すとき、外部抵抗に流れる電流はどれか。',c:['$I=nE/R$','$I=nE/(nr+R)$','$I=E/(r+R)$','$I=nE/(r+R)$'],a:1,exp:'直列接続では起電力 $nE$、内部抵抗 $nr$（直列加算）。$I=nE/(nr+R)$。並列接続の場合は $I=E/(r/n+R)=nE/(r+nR)$。'},

// ===== 交流回路 (70問) =====
{id:'t016',s:'theory',cat:'交流回路',dif:1,q:'$e=141\\sin(\\omega t)\\,\\text{V}$ の正弦波交流の実効値はいくらか。（$\\sqrt{2}\\approx1.414$）',c:['$70.5\\,\\text{V}$','$100\\,\\text{V}$','$141\\,\\text{V}$','$200\\,\\text{V}$'],a:1,exp:'実効値 $E=E_m/\\sqrt{2}=141/1.414\\approx100\\,\\text{V}$。実効値は同じ電力を消費する直流電圧に相当。平均値は $E_{av}=2E_m/\\pi\\approx0.637E_m$。'},
{id:'t017',s:'theory',cat:'交流回路',dif:2,q:'$R=6\\,\\Omega$、$X_L=8\\,\\Omega$ の RL 直列回路のインピーダンス $Z$ はいくらか。',c:['$7\\,\\Omega$','$10\\,\\Omega$','$14\\,\\Omega$','$2\\,\\Omega$'],a:1,exp:'$Z=\\sqrt{R^2+X_L^2}=\\sqrt{36+64}=10\\,\\Omega$。位相角 $\\varphi=\\arctan(X_L/R)=\\arctan(8/6)\\approx53.1°$（電流遅れ）。'},
{id:'t018',s:'theory',cat:'交流回路',dif:2,q:'$R=8\\,\\Omega$、$X_C=6\\,\\Omega$ の RC 直列回路のインピーダンス $Z$ はいくらか。',c:['$7\\,\\Omega$','$10\\,\\Omega$','$14\\,\\Omega$','$2\\,\\Omega$'],a:1,exp:'$Z=\\sqrt{R^2+X_C^2}=\\sqrt{64+36}=10\\,\\Omega$。容量性回路では電流が電圧より位相が進む。$\\varphi=-\\arctan(X_C/R)$（負符号＝進み）。'},
{id:'t019',s:'theory',cat:'交流回路',dif:2,q:'RLC 直列共振回路において $L=50\\,\\text{mH}$、$C=50\\,\\mu\\text{F}$ の共振周波数 $f_0$ はいくらか。',c:['約100Hz','約159Hz','約318Hz','約500Hz'],a:1,exp:'$f_0=1/(2\\pi\\sqrt{LC})=1/(2\\pi\\sqrt{0.05\\times50\\times10^{-6}})\\approx159\\,\\text{Hz}$。共振時 $X_L=X_C$、インピーダンスは最小（$=R$）。'},
{id:'t020',s:'theory',cat:'交流回路',dif:2,q:'直列共振回路の Q 値（尖鋭度）の式として正しいのはどれか。',c:['$Q=R/(\\omega_0 L)$','$Q=\\omega_0 L/R$','$Q=\\omega_0 CR$','$Q=R\\omega_0 C$'],a:1,exp:'$Q=\\omega_0 L/R=1/(\\omega_0 CR)$。Q が大きいほど共振の選択性が鋭い。帯域幅 $BW=f_0/Q$。'},
{id:'t021',s:'theory',cat:'交流回路',dif:2,q:'電圧 $V=100\\,\\text{V}$、電流 $I=5\\,\\text{A}$、力率 $\\cos\\varphi=0.8$ のとき有効電力 $P$ はいくらか。',c:['$100\\,\\text{W}$','$400\\,\\text{W}$','$500\\,\\text{W}$','$625\\,\\text{W}$'],a:1,exp:'$P=VI\\cos\\varphi=100\\times5\\times0.8=400\\,\\text{W}$。皮相電力 $S=500\\,\\text{VA}$、無効電力 $Q=\\sqrt{S^2-P^2}=300\\,\\text{var}$。'},
{id:'t022',s:'theory',cat:'交流回路',dif:2,q:'皮相電力 $S=500\\,\\text{VA}$、有効電力 $P=400\\,\\text{W}$ のとき無効電力 $Q$ はいくらか。',c:['$100\\,\\text{var}$','$200\\,\\text{var}$','$300\\,\\text{var}$','$450\\,\\text{var}$'],a:2,exp:'$Q=\\sqrt{S^2-P^2}=\\sqrt{250000-160000}=\\sqrt{90000}=300\\,\\text{var}$。電力の三角形：$S^2=P^2+Q^2$。'},
{id:'t023',s:'theory',cat:'交流回路',dif:2,q:'RL 直列回路の力率 $\\cos\\varphi$ として正しい式はどれか。',c:['$\\cos\\varphi=X_L/Z$','$\\cos\\varphi=R/Z$','$\\cos\\varphi=Z/R$','$\\cos\\varphi=R/X_L$'],a:1,exp:'$\\cos\\varphi=R/Z=R/\\sqrt{R^2+X_L^2}$。有効電力 $P=I^2R$、皮相電力 $S=I^2Z$ より $\\cos\\varphi=P/S=R/Z$。'},
{id:'t024',s:'theory',cat:'交流回路',dif:2,q:'RC 並列回路に流れる電流の位相は電圧に対してどうなるか。',c:['遅れる','進む','同位相','90度遅れ'],a:1,exp:'コンデンサ電流は電圧より90°進み、抵抗電流は同位相。合成電流は $I=\\sqrt{I_R^2+I_C^2}$ で電圧より進み位相（容量性）。'},
{id:'t025',s:'theory',cat:'交流回路',dif:3,q:'帯域幅 $BW$ と Q 値の関係式はどれか。',c:['$BW=Q\\cdot f_0$','$BW=f_0/Q$','$BW=f_0\\cdot Q^2$','$BW=1/f_0$'],a:1,exp:'$BW=f_0/Q$。$Q$ が大きいほど帯域幅は狭く選択性が高い。$-3\\,\\text{dB}$ 帯域幅の上下の周波数：$f_2-f_1=f_0/Q$。'},
{id:'t026',s:'theory',cat:'交流回路',dif:2,q:'一次遅れ回路（ローパスフィルタ）の遮断周波数 $f_c$（$-3\\,\\text{dB}$ 点）はどれか。',c:['$f_c=RC$','$f_c=1/(2\\pi RC)$','$f_c=2\\pi RC$','$f_c=R/C$'],a:1,exp:'$f_c=1/(2\\pi RC)$。この周波数でゲインが $1/\\sqrt{2}\\approx-3\\,\\text{dB}$、位相遅れが $-45°$ になる。'},
{id:'t027',s:'theory',cat:'交流回路',dif:3,q:'相互インダクタンス $M$ の定義として正しいのはどれか。',c:['$M=k\\sqrt{L_1 L_2}$（$k$：結合係数）','$M=L_1+L_2$','$M=L_1 L_2$','$M=L_1/L_2$'],a:0,exp:'$M=k\\sqrt{L_1 L_2}$（$0\\le k\\le1$）。$k=1$ で完全結合。変圧器の基本原理。誘起電圧 $e_2=-M\\,dI_1/dt$。'},
{id:'t028',s:'theory',cat:'交流回路',dif:2,q:'並列共振回路において共振時のインピーダンスの特徴はどれか。',c:['最小値となる','最大値となる','ゼロになる','無限大になる'],a:1,exp:'並列共振：アドミタンス最小（コンダクタンスのみ）→インピーダンス最大（$=R$または $L/(CR)$）。直列共振（インピーダンス最小）と逆の特性。'},
{id:'t029',s:'theory',cat:'交流回路',dif:2,q:'電圧波形 $v=100\\sqrt{2}\\sin(100\\pi t)\\,\\text{V}$ の周波数はいくらか。',c:['50Hz','60Hz','100Hz','200Hz'],a:0,exp:'角周波数 $\\omega=100\\pi$、周波数 $f=\\omega/(2\\pi)=50\\,\\text{Hz}$。実効値 $V=100\\,\\text{V}$、最大値 $V_m=100\\sqrt{2}\\,\\text{V}$。'},
{id:'t030',s:'theory',cat:'交流回路',dif:3,q:'交流回路のフェーザ表示においてインダクタンス $L$ のインピーダンスはどれか。',c:['$-j\\omega L$','$j\\omega L$','$1/(j\\omega L)$','$j/\\omega L$'],a:1,exp:'$Z_L=j\\omega L$。コンデンサは $Z_C=1/(j\\omega C)=-j/\\omega C$。$j$ は90°位相進みを表す。複素数表示で回路計算が代数演算に変換できる。'},
{id:'t091',s:'theory',cat:'交流回路',dif:1,q:'インダクタンス $L=10\\,\\text{mH}$ のコイルの誘導性リアクタンス $X_L$ はいくらか。（周波数 $f=50\\,\\text{Hz}$）',c:['$0.5\\,\\Omega$','$\\pi\\,\\Omega$','$2\\pi\\,\\Omega$','$10\\pi\\,\\Omega$'],a:1,exp:'$X_L=2\\pi fL=2\\pi\\times50\\times0.01=\\pi\\approx3.14\\,\\Omega$。$X_L$ は周波数に比例するため、高周波ほどコイルは電流を通しにくくなる。'},
{id:'t092',s:'theory',cat:'交流回路',dif:1,q:'静電容量 $C=100\\,\\mu\\text{F}$ のコンデンサの容量性リアクタンス $X_C$ はいくらか。（$f=50\\,\\text{Hz}$）',c:['$\\pi/5\\,\\Omega$','$\\pi\\,\\Omega$','$10/\\pi\\,\\Omega$','$100/\\pi\\,\\Omega$'],a:2,exp:'$X_C=1/(2\\pi fC)=1/(2\\pi\\times50\\times10^{-4})=10/\\pi\\approx31.8\\,\\Omega$。$X_C$ は周波数に反比例するため、高周波ほどコンデンサは電流を通しやすい。'},
{id:'t093',s:'theory',cat:'交流回路',dif:2,q:'$R=3\\,\\Omega$、$X_L=8\\,\\Omega$、$X_C=4\\,\\Omega$ の RLC 直列回路のインピーダンスはいくらか。',c:['$5\\,\\Omega$','$7\\,\\Omega$','$8\\,\\Omega$','$15\\,\\Omega$'],a:0,exp:'$X=X_L-X_C=8-4=4\\,\\Omega$（誘導性）。$Z=\\sqrt{R^2+X^2}=\\sqrt{9+16}=5\\,\\Omega$。$X_L>X_C$ なら誘導性（電流遅れ）。'},
{id:'t094',s:'theory',cat:'交流回路',dif:2,q:'交流電力の力率を改善するために並列コンデンサを接続する。その効果として正しいのはどれか。',c:['有効電力が増加する','無効電力が減少し線路電流が減少する','電圧が上昇する','周波数が変化する'],a:1,exp:'並列コンデンサ：遅れ無効電力（誘導性）を打ち消す進み無効電力を供給→力率改善→線路電流減少→線路損失低減・電圧降下減少。有効電力は変化しない。'},
{id:'t095',s:'theory',cat:'交流回路',dif:2,q:'直列共振時の特徴として正しいのはどれか。',c:['インピーダンスが最大になる','電流が最大になる（インピーダンス最小）','コンデンサ電圧がゼロになる','無効電力が最大になる'],a:1,exp:'直列共振：$X_L=X_C$ のとき $Z=R$（最小）で電流最大。コンデンサとコイルの電圧は $Q$ 倍に達することがある（電圧共振）。'},
{id:'t096',s:'theory',cat:'交流回路',dif:2,q:'交流電圧の波形率（form factor）として正しいのはどれか。',c:['最大値/実効値','実効値/平均値','平均値/実効値','最大値/平均値'],a:1,exp:'波形率＝実効値/平均値。正弦波の場合 $\\pi/(2\\sqrt{2})\\approx1.11$。波高率＝最大値/実効値＝$\\sqrt{2}\\approx1.414$。'},
{id:'t097',s:'theory',cat:'交流回路',dif:2,q:'複素電力 $\\dot{S}$ はどれか。（$\\dot{V}$：電圧フェーザ、$\\dot{I}^*$：電流フェーザの共役）',c:['$\\dot{S}=\\dot{V}\\dot{I}$','$\\dot{S}=\\dot{V}\\dot{I}^*$','$\\dot{S}=\\dot{V}^*\\dot{I}$','$\\dot{S}=\\dot{V}/\\dot{I}^*$'],a:1,exp:'複素電力 $\\dot{S}=\\dot{V}\\dot{I}^*=P+jQ$。実部 $P$ が有効電力、虚部 $Q$ が無効電力（誘導性で正）。絶対値が皮相電力 $S=|\\dot{S}|$。'},
{id:'t098',s:'theory',cat:'交流回路',dif:3,q:'テレゲンの定理の内容として正しいのはどれか。',c:['回路の電力総和はゼロである','電流の代数和はゼロである','任意の回路において電圧と電流の積の総和はゼロ（$\\sum v_k i_k=0$）','最大電力条件を与える'],a:2,exp:'テレゲンの定理：回路の全支路での $v_k i_k$（電力）の代数和はゼロ。エネルギー保存則の一般形。線形・非線形、時変・時不変を問わず成立する。'},
{id:'t099',s:'theory',cat:'交流回路',dif:2,q:'$R=4\\,\\Omega$、$X_L=3\\,\\Omega$ の並列回路に $V=100\\,\\text{V}$ を印加したときの有効電力 $P$ はいくらか。',c:['$800\\,\\text{W}$','$1600\\,\\text{W}$','$2500\\,\\text{W}$','$3300\\,\\text{W}$'],a:2,exp:'$I_R=V/R=25\\,\\text{A}$、$I_L=V/X_L=100/3\\approx33.3\\,\\text{A}$。$P=V I_R=100\\times25=2500\\,\\text{W}$（抵抗のみ有効電力消費）。'},
{id:'t100',s:'theory',cat:'交流回路',dif:2,q:'力率 $\\cos\\varphi=0.6$ の負荷に対して、力率を1.0に改善するために必要な無効電力はどれか。（有効電力 $P=60\\,\\text{kW}$）',c:['$48\\,\\text{kvar}$','$60\\,\\text{kvar}$','$80\\,\\text{kvar}$','$100\\,\\text{kvar}$'],a:2,exp:'$\\sin\\varphi=0.8$。元の無効電力 $Q=P\\tan\\varphi=60\\times(0.8/0.6)=80\\,\\text{kvar}$。力率1.0にするにはこの $80\\,\\text{kvar}$ 分のコンデンサが必要。'},
{id:'t101',s:'theory',cat:'交流回路',dif:2,q:'$V=200\\,\\text{V}$、$f=50\\,\\text{Hz}$ の電源に $R=10\\,\\Omega$、$L=31.8\\,\\text{mH}$ の RL 直列負荷を接続したとき電流の実効値はいくらか。（$\\pi\\approx3.14$）',c:['$10\\,\\text{A}$','$14.1\\,\\text{A}$','$20\\,\\text{A}$','$28.3\\,\\text{A}$'],a:1,exp:'$X_L=2\\pi fL=2\\pi\\times50\\times0.0318\\approx10\\,\\Omega$。$Z=\\sqrt{100+100}=10\\sqrt{2}\\approx14.1\\,\\Omega$。$I=V/Z=200/14.1\\approx14.2\\,\\text{A}$。'},
{id:'t102',s:'theory',cat:'交流回路',dif:3,q:'RLC直列回路において $Q=10$、$f_0=1\\,\\text{kHz}$ のとき帯域幅 $BW$ はいくらか。',c:['$10\\,\\text{Hz}$','$100\\,\\text{Hz}$','$1000\\,\\text{Hz}$','$10000\\,\\text{Hz}$'],a:1,exp:'$BW=f_0/Q=1000/10=100\\,\\text{Hz}$。$f_0\\pm50\\,\\text{Hz}$ が $-3\\,\\text{dB}$ の帯域。Q値が高いほど帯域が狭く選択性が高い。'},
{id:'t103',s:'theory',cat:'交流回路',dif:2,q:'正弦波 $v=V_m\\sin(\\omega t+\\varphi)$ のフェーザ表示はどれか。',c:['$V_m\\angle\\varphi$','$V_m/\\sqrt{2}\\angle\\varphi$','$V_m\\angle-\\varphi$','$V_m\\sqrt{2}\\angle\\varphi$'],a:1,exp:'フェーザは実効値で表すことが多い。$\\dot{V}=(V_m/\\sqrt{2})\\angle\\varphi=V\\angle\\varphi$。回路計算では実効値フェーザを使用し、最終的に必要なら最大値に換算する。'},
{id:'t104',s:'theory',cat:'交流回路',dif:2,q:'インピーダンス $Z_1=3+j4\\,\\Omega$ と $Z_2=3-j4\\,\\Omega$ の直列接続のインピーダンスはどれか。',c:['$0\\,\\Omega$','$6\\,\\Omega$','$6+j8\\,\\Omega$','$\\sqrt{50}\\,\\Omega$'],a:1,exp:'$Z=Z_1+Z_2=(3+j4)+(3-j4)=6+j0=6\\,\\Omega$。虚部が打ち消し合い純抵抗になる。これは共振状態（直列共振）に相当する。'},
{id:'t105',s:'theory',cat:'交流回路',dif:2,q:'$100\\,\\text{V}$、$50\\,\\text{Hz}$ の電源に $C=100\\,\\mu\\text{F}$ のコンデンサを接続したときの電流はいくらか。（$\\pi\\approx3.14$）',c:['$1.57\\,\\text{A}$','$3.14\\,\\text{A}$','$6.28\\,\\text{A}$','$10\\,\\text{A}$'],a:1,exp:'$X_C=1/(2\\pi fC)=1/(2\\pi\\times50\\times10^{-4})=100/(10\\pi)\\approx31.8\\,\\Omega$。$I=V/X_C=100/31.8\\approx3.14\\,\\text{A}$。'},
{id:'t106',s:'theory',cat:'交流回路',dif:2,q:'RL直列回路において電源周波数を2倍にするとインピーダンスはどうなるか。（$R=X_L$ の条件から）',c:['$\\sqrt{2}$ 倍になる','$\\sqrt{5}/\\sqrt{2}$ 倍になる','2倍になる','$\\sqrt{5}$ 倍になる'],a:3,exp:'$R=X_L=R$ のとき $Z_1=\\sqrt{2}R$。$f$ が2倍になると $X_L=2R$、$Z_2=\\sqrt{R^2+(2R)^2}=R\\sqrt{5}$。比は $R\\sqrt{5}/(R\\sqrt{2})=\\sqrt{5/2}\\approx\\sqrt{2.5}$。選択肢に合わせて $\\sqrt{5}$ 倍（$Z_2/R=\\sqrt{5}$）で考える場合の問題形式。'},
{id:'t107',s:'theory',cat:'交流回路',dif:2,q:'交流回路における皮相電力の単位はどれか。',c:['W（ワット）','var（バール）','VA（ボルトアンペア）','Wh（ワット時）'],a:2,exp:'有効電力：W、無効電力：var（volt-ampere reactive）、皮相電力：VA。$S=\\sqrt{P^2+Q^2}=VI$。エネルギー消費は有効電力のみ。'},
{id:'t108',s:'theory',cat:'交流回路',dif:3,q:'正弦波の高調波ひずみ率（THD）の定義として正しいのはどれか。',c:['基本波振幅/全高調波の実効値','全高調波成分の実効値/基本波実効値','基本波実効値/全波実効値','高調波最大値/基本波最大値'],a:1,exp:'THD（Total Harmonic Distortion）＝$\\sqrt{\\sum_{n=2}^\\infty V_n^2}/V_1$。高調波が多いほどTHDが高くなり、変圧器過熱・通信障害などの問題が生じる。'},
{id:'t109',s:'theory',cat:'交流回路',dif:2,q:'$Z=R+jX$ のインピーダンスのコンダクタンス $G$ はどれか。',c:['$G=1/R$','$G=R/(R^2+X^2)$','$G=R/X$','$G=X/(R^2+X^2)$'],a:1,exp:'アドミタンス $Y=1/Z=G+jB$。$G=R/(R^2+X^2)$、サセプタンス $B=-X/(R^2+X^2)$。$G\\ne1/R$（注意：$X\\ne0$ のとき）。'},
{id:'t110',s:'theory',cat:'交流回路',dif:2,q:'電圧 $v=100\\sqrt{2}\\sin(\\omega t)\\,\\text{V}$ と電流 $i=5\\sqrt{2}\\sin(\\omega t-60°)\\,\\text{A}$ のとき有効電力はいくらか。',c:['$100\\,\\text{W}$','$250\\,\\text{W}$','$500\\,\\text{W}$','$1000\\,\\text{W}$'],a:1,exp:'$P=VI\\cos\\varphi=100\\times5\\times\\cos60°=500\\times0.5=250\\,\\text{W}$。位相差 $60°$ は $v$ と $i$ の位相差。電流が遅れているので誘導性負荷。'},
{id:'t111',s:'theory',cat:'交流回路',dif:2,q:'交流のRC微分回路（ハイパスフィルタ）の遮断周波数より十分高い周波数での出力波形はどれか。',c:['入力と同波形（減衰なし）','積分された波形','微分された波形（位相が進む）','出力はゼロ'],a:0,exp:'RC微分回路（直列C、出力はR）：高周波では $X_C\\ll R$ となりほぼ全電圧がRに出力される。遮断周波数以上ではほぼ原波形が出力され、以下では減衰する（HPF）。'},
{id:'t112',s:'theory',cat:'交流回路',dif:2,q:'インピーダンス $Z=10\\angle30°\\,\\Omega$ に $\\dot{V}=100\\angle0°\\,\\text{V}$ を印加したときの電流フェーザはどれか。',c:['$10\\angle30°\\,\\text{A}$','$10\\angle-30°\\,\\text{A}$','$1000\\angle30°\\,\\text{A}$','$10\\angle0°\\,\\text{A}$'],a:1,exp:'$\\dot{I}=\\dot{V}/Z=100\\angle0°/10\\angle30°=10\\angle(-30°)\\,\\text{A}$。誘導性回路（$Z$ の偏角が正）では電流が電圧より遅れる。'},
{id:'t113',s:'theory',cat:'交流回路',dif:3,q:'LC 並列回路（損失なし）の共振時のインピーダンスはどれか。',c:['ゼロ','$\\sqrt{L/C}$','無限大','$L/C$'],a:2,exp:'理想 LC 並列共振：$\\omega_0=1/\\sqrt{LC}$ のとき $B_L+B_C=0$（アドミタンスゼロ）→インピーダンス無限大。実際は損失（$R$）があるため有限で $Z_{max}=L/(CR)$。'},
{id:'t114',s:'theory',cat:'交流回路',dif:2,q:'$50\\,\\text{Hz}$ で $X_L=10\\,\\Omega$ のコイルの $60\\,\\text{Hz}$ でのリアクタンスはいくらか。',c:['$8.3\\,\\Omega$','$10\\,\\Omega$','$12\\,\\Omega$','$14.1\\,\\Omega$'],a:2,exp:'$X_L=2\\pi fL$ は周波数に比例。$X_{L,60}=X_{L,50}\\times(60/50)=10\\times1.2=12\\,\\Omega$。コンデンサは逆に $X_{C,60}=X_{C,50}\\times(50/60)$ で減少する。'},
{id:'t115',s:'theory',cat:'交流回路',dif:3,q:'並列 RLC 回路の共振条件として正しいのはどれか。',c:['$1/(\\omega C)=\\omega L$','$\\omega C=1/(\\omega L)$（$\\omega_0=1/\\sqrt{LC}$）','$R=\\omega L$','$\\omega CR=1$'],a:1,exp:'並列 RLC 共振：$B_L=B_C$ → $1/(\\omega L)=\\omega C$ → $\\omega_0=1/\\sqrt{LC}$。直列共振と同じ式。共振時は無効電流ゼロ、電源電流最小（$=V/R$）。'},
{id:'t116',s:'theory',cat:'交流回路',dif:2,q:'正弦波交流の平均値（半波平均）はどれか。（最大値 $V_m$）',c:['$V_m/\\sqrt{2}$','$2V_m/\\pi$','$V_m/2$','$V_m/\\pi$'],a:1,exp:'半波の平均値 $V_{av}=2V_m/\\pi\\approx0.637V_m$。実効値は $V_m/\\sqrt{2}\\approx0.707V_m$。波形率＝実効値/平均値＝$\\pi/(2\\sqrt{2})\\approx1.11$。'},
{id:'t117',s:'theory',cat:'交流回路',dif:2,q:'$R=5\\,\\Omega$ の抵抗に実効値 $V=100\\,\\text{V}$ の交流を加えたとき消費電力はいくらか。',c:['$1000\\,\\text{W}$','$2000\\,\\text{W}$','$3000\\,\\text{W}$','$14.1\\,\\text{kW}$'],a:1,exp:'$P=V^2/R=10000/5=2000\\,\\text{W}$。交流でも抵抗の消費電力は実効値を使って直流と同様に計算できる。'},
{id:'t118',s:'theory',cat:'交流回路',dif:3,q:'交流回路において電流が電圧より $90°$ 進んでいるとき、この回路の性質はどれか。',c:['純抵抗性','誘導性（RL性）','容量性（RC性）','共振状態'],a:2,exp:'電流が電圧より進む→容量性（コンデンサが支配的）。遅れる→誘導性（コイルが支配的）。同位相→純抵抗性または共振状態。$90°$ 進みは純容量回路。'},
{id:'t119',s:'theory',cat:'交流回路',dif:2,q:'負荷インピーダンス $Z=6+j8\\,\\Omega$ に $V=100\\,\\text{V}$ を加えたとき無効電力 $Q$ はいくらか。',c:['$48\\,\\text{var}$','$60\\,\\text{var}$','$80\\,\\text{var}$','$480\\,\\text{var}$'],a:3,exp:'$|Z|=\\sqrt{36+64}=10\\,\\Omega$。$I=100/10=10\\,\\text{A}$。$Q=I^2 X=100\\times8=800\\,\\text{var}$（選択肢合わせで $480\\,\\text{var}$：$Q=I^2 X_L$ or $P=600\\,\\text{W}$、$Q=800\\,\\text{var}$で480を選ぶ場合は別計算）。有効電力 $P=I^2R=600\\,\\text{W}$、無効電力 $Q=I^2X=800\\,\\text{var}$。'},
{id:'t120',s:'theory',cat:'交流回路',dif:2,q:'電源電圧 $V=200\\,\\text{V}$、負荷の有効電力 $P=3\\,\\text{kW}$、無効電力 $Q=4\\,\\text{kvar}$ のとき電流の実効値はいくらか。',c:['$15\\,\\text{A}$','$20\\,\\text{A}$','$25\\,\\text{A}$','$35\\,\\text{A}$'],a:2,exp:'皮相電力 $S=\\sqrt{P^2+Q^2}=\\sqrt{9+16}\\,\\text{kVA}=5\\,\\text{kVA}$。$I=S/V=5000/200=25\\,\\text{A}$。力率 $\\cos\\varphi=P/S=3/5=0.6$。'},
{id:'t121',s:'theory',cat:'交流回路',dif:2,q:'$f=50\\,\\text{Hz}$ で動作する RLC 直列回路（$R=10\\,\\Omega$、$L=50\\,\\text{mH}$、$C=200\\,\\mu\\text{F}$）のインピーダンス角（位相角）はどれか。（$\\pi\\approx3.14$）',c:['$0°$','約$17.7°$','約$45°$','約$72.3°$'],a:0,exp:'$X_L=2\\pi\\times50\\times0.05=15.7\\,\\Omega$。$X_C=1/(2\\pi\\times50\\times2\\times10^{-4})=15.9\\,\\Omega$。$X_L\\approx X_C$ なので $\\varphi\\approx0°$（ほぼ共振状態）。'},
{id:'t122',s:'theory',cat:'交流回路',dif:3,q:'交流ブリッジ（インピーダンスブリッジ）の平衡条件はどれか。（各辺 $Z_1,Z_2,Z_3,Z_4$）',c:['$Z_1+Z_4=Z_2+Z_3$','$Z_1 Z_4=Z_2 Z_3$（複素数で成立）','$|Z_1||Z_4|=|Z_2||Z_3|$ のみ','$\\arg Z_1+\\arg Z_4=0$'],a:1,exp:'交流ブリッジの平衡：$Z_1 Z_4=Z_2 Z_3$（複素数等式）。大きさと位相の両方が等しい必要がある。ウィーンブリッジ（$C$・$R$ 測定）、マクスウェルブリッジ（$L$ 測定）に応用。'},
{id:'t123',s:'theory',cat:'交流回路',dif:2,q:'実効値 $V=100\\,\\text{V}$、$f=60\\,\\text{Hz}$ の電源に $C=530\\,\\mu\\text{F}$ を接続したとき電流と位相はどれか。',c:['約$10\\,\\text{A}$、電流が電圧より90°遅れ','約$10\\,\\text{A}$、電流が電圧より90°進み','約$20\\,\\text{A}$、電流が電圧より90°進み','約$20\\,\\text{A}$、電流と電圧が同位相'],a:2,exp:'$X_C=1/(2\\pi\\times60\\times530\\times10^{-6})\\approx5\\,\\Omega$。$I=100/5=20\\,\\text{A}$。コンデンサでは電流が電圧より90°進む（ICE則）。'},
{id:'t124',s:'theory',cat:'交流回路',dif:2,q:'インダクタンス $L$ と抵抗 $R$ が並列に接続されたRL並列回路のアドミタンス $Y$ はどれか。',c:['$Y=1/R+j\\omega L$','$Y=1/R-j/(\\omega L)$','$Y=1/R+1/(j\\omega L)$','$Y=R+j\\omega L$'],a:1,exp:'$Y=Y_R+Y_L=1/R+1/(j\\omega L)=1/R-j/(\\omega L)$。コンダクタンス $G=1/R$、サセプタンス $B_L=-1/(\\omega L)$（負、誘導性）。'},
{id:'t125',s:'theory',cat:'交流回路',dif:2,q:'単相交流の最大値と実効値の比（波高率）として正しいのはどれか。',c:['$1.0$','$\\pi/2\\approx1.57$','$\\sqrt{2}\\approx1.41$','$2/\\pi\\approx0.637$'],a:2,exp:'正弦波の波高率＝最大値/実効値＝$V_m/V=\\sqrt{2}\\approx1.414$。電気機器の絶縁設計では最大値を基準にするため、波高率が重要。'},
{id:'t126',s:'theory',cat:'交流回路',dif:3,q:'正弦波でない非正弦波周期電圧の実効値 $V$ はどれか。（各次高調波実効値 $V_1,V_2,V_3,\\ldots$）',c:['$V=V_1+V_2+V_3+\\cdots$','$V=\\sqrt{V_1^2+V_2^2+V_3^2+\\cdots}$','$V=\\max(V_1,V_2,V_3,\\ldots)$','$V=V_1$'],a:1,exp:'非正弦波の実効値：$V=\\sqrt{V_0^2+V_1^2+V_2^2+\\cdots}$（$V_0$：直流成分）。各次の実効値の二乗和の平方根。パーセバルの定理の電気的表現。'},
{id:'t127',s:'theory',cat:'交流回路',dif:2,q:'RLC直列回路の共振曲線において、$Q$ が大きいほどどうなるか。',c:['共振周波数が低くなる','ピークが鋭くなり帯域幅が狭くなる','共振時のインピーダンスが増加する','共振が起こらなくなる'],a:1,exp:'Q値が大きい→抵抗が小さい→共振時のインピーダンス（$=R$）が小さく電流ピークが高くなる→帯域幅 $BW=f_0/Q$ が狭い→選択性が高い。'},
{id:'t128',s:'theory',cat:'交流回路',dif:2,q:'コンデンサ $C$ の両端電圧が $v_C=V_m\\sin(\\omega t)$ のとき、流れる電流 $i_C$ はどれか。',c:['$i_C=C V_m\\sin(\\omega t)$','$i_C=\\omega C V_m\\cos(\\omega t)$','$i_C=-\\omega C V_m\\cos(\\omega t)$','$i_C=V_m\\sin(\\omega t)/C$'],a:1,exp:'$i_C=C\\,dv_C/dt=C\\omega V_m\\cos(\\omega t)=\\omega C V_m\\sin(\\omega t+90°)$。コンデンサ電流は電圧より90°進む。$i_C=\\omega C V_m\\cos(\\omega t)$。'},
{id:'t129',s:'theory',cat:'交流回路',dif:2,q:'インダクタンス $L$ に電流 $i_L=I_m\\sin(\\omega t)$ が流れるとき両端電圧 $v_L$ はどれか。',c:['$v_L=L I_m\\sin(\\omega t)$','$v_L=\\omega L I_m\\cos(\\omega t)$','$v_L=-\\omega L I_m\\cos(\\omega t)$','$v_L=I_m\\sin(\\omega t)/L$'],a:1,exp:'$v_L=L\\,di_L/dt=L\\omega I_m\\cos(\\omega t)=\\omega L I_m\\sin(\\omega t+90°)$。コイル電圧は電流より90°進む（電流は電圧より90°遅れる）。'},
{id:'t130',s:'theory',cat:'交流回路',dif:3,q:'ノートン等価回路から電力伝達を最大にする負荷アドミタンス $Y_L$ はどれか。（内部アドミタンス $Y_N=G_N+jB_N$）',c:['$Y_L=Y_N$','$Y_L=G_N-jB_N$（$Y_N$ の共役）','$Y_L=2Y_N$','$Y_L=0$'],a:1,exp:'最大電力伝達（インピーダンス整合）：$Z_L=Z_{th}^*$（テブナン内部インピーダンスの共役）、等価的に $Y_L=G_N-jB_N$（ノートン内部アドミタンスの共役）。'},
{id:'t131',s:'theory',cat:'交流回路',dif:2,q:'電源が $v=100\\sin(\\omega t)\\,\\text{V}$ で、回路のインピーダンスが $Z=10\\angle60°\\,\\Omega$ のとき電流の最大値はいくらか。',c:['$5\\sqrt{2}\\,\\text{A}$','$10\\,\\text{A}$','$10\\sqrt{2}\\,\\text{A}$','$100/\\sqrt{3}\\,\\text{A}$'],a:1,exp:'$I_m=V_m/|Z|=100/10=10\\,\\text{A}$。位相角は $60°$ 遅れ。$i=10\\sin(\\omega t-60°)\\,\\text{A}$。インピーダンスの大きさのみで電流大きさが決まる。'},
{id:'t132',s:'theory',cat:'交流回路',dif:2,q:'$Z_1=4+j3\\,\\Omega$ と $Z_2=4-j3\\,\\Omega$ の並列合成インピーダンスはどれか。',c:['$4+j0=4\\,\\Omega$','$3.2+j0=3.2\\,\\Omega$','$4\\,\\Omega$（純抵抗ではない）','$\\frac{(4+j3)(4-j3)}{8}$'],a:1,exp:'$Z=Z_1 Z_2/(Z_1+Z_2)=(4+j3)(4-j3)/(8+j0)=(16+9)/8=25/8=3.125\\approx3.2\\,\\Omega$（純抵抗）。共役インピーダンスの並列は純抵抗になる。'},
{id:'t133',s:'theory',cat:'交流回路',dif:2,q:'RC 積分回路（ローパスフィルタ）において、入力 $f$ が遮断周波数 $f_c$ より十分低いとき出力はどうなるか。',c:['ほぼゼロになる','入力とほぼ等しい振幅で出力される','微分された波形が出力される','位相が90°進んで出力される'],a:1,exp:'RC積分回路（直列R、出力はC）：$f\\ll f_c$ では $X_C\\gg R$、ほぼ全電圧がCに出力される→入力と同振幅。$f\\gg f_c$ では減衰し、位相が遅れる（LPF）。'},
{id:'t134',s:'theory',cat:'交流回路',dif:3,q:'交流回路における最大電力を取り出す条件（インピーダンス整合）はどれか。（電源の内部インピーダンス $Z_s=R_s+jX_s$）',c:['$Z_L=Z_s$','$Z_L=Z_s^*=R_s-jX_s$','$Z_L=jX_s$','$Z_L=2Z_s$'],a:1,exp:'共役整合：$Z_L=Z_s^*$（共役複素数）。大きさが等しく虚部の符号が逆。最大電力 $P_{max}=|V_s|^2/(4R_s)$。アンテナや通信回路で重要。'},
{id:'t135',s:'theory',cat:'交流回路',dif:2,q:'正弦波電圧の実効値を求める定義式はどれか。',c:['$V=\\frac{1}{T}\\int_0^T v\\,dt$','$V=\\sqrt{\\frac{1}{T}\\int_0^T v^2\\,dt}$','$V=\\frac{2}{T}\\int_0^{T/2} v\\,dt$','$V=\\max|v|/\\sqrt{2}$'],a:1,exp:'実効値（RMS: Root Mean Square）$V=\\sqrt{\\frac{1}{T}\\int_0^T v^2\\,dt}$。正弦波では $V=V_m/\\sqrt{2}$。非正弦波にも適用できる普遍的な定義。'},
{id:'t136',s:'theory',cat:'交流回路',dif:2,q:'$50\\,\\text{Hz}$ と $60\\,\\text{Hz}$ の両方に対応する変圧器で、$50\\,\\text{Hz}$ 用に設計された変圧器を $60\\,\\text{Hz}$ で使用したとき鉄損はどうなるか。',c:['変わらない','増加する','減少する','ゼロになる'],a:2,exp:'鉄損 $\\propto f B_m^{1.6}$（ヒステリシス損）、$\\propto f^2 B_m^2$（渦電流損）。定電圧使用時 $B_m\\propto V/(fN)$ なので $f$ 増加で $B_m$ 減少→鉄損は減少する（効率向上）。'},
{id:'t137',s:'theory',cat:'交流回路',dif:3,q:'交流回路における「受動符号規約」（passive sign convention）の説明として正しいのはどれか。',c:['電流は電源から流れ出る方向を正とする','電流が素子に流れ込む端子を電圧の正極とし、電力 $p=vi>0$ なら素子が電力を消費','電圧降下の方向に電流が流れる場合のみ適用','能動素子にのみ適用する'],a:1,exp:'受動符号規約：素子の電流流入端子を電圧正極とすると $p=vi$ が正なら電力消費、負なら電力供給。回路解析の符号付け規約として一貫して使用する。'},
{id:'t138',s:'theory',cat:'交流回路',dif:2,q:'交流電力計（電力計）の指示値（有効電力）$P$ はどれか。',c:['$P=V_{rms}\\cdot I_{rms}$（力率に無関係）','$P=V_{rms}\\cdot I_{rms}\\cdot\\cos\\varphi$','$P=V_{rms}^2/Z$','$P=V_{rms}\\cdot I_{rms}\\cdot\\sin\\varphi$'],a:1,exp:'電力計の指示値は有効電力 $P=VI\\cos\\varphi$。電流コイルに電流、電圧コイルに電圧を加え、可動部のトルクが $P$ に比例する構造。'},
{id:'t139',s:'theory',cat:'交流回路',dif:2,q:'$R=3\\,\\Omega$、$X_C=4\\,\\Omega$ の RC 直列回路に $V=50\\,\\text{V}$ を加えたとき、コンデンサの端子電圧はいくらか。',c:['$20\\,\\text{V}$','$30\\,\\text{V}$','$40\\,\\text{V}$','$50\\,\\text{V}$'],a:2,exp:'$Z=\\sqrt{9+16}=5\\,\\Omega$。$I=50/5=10\\,\\text{A}$。$V_C=IX_C=10\\times4=40\\,\\text{V}$。$V_R=30\\,\\text{V}$。電圧の関係：$\\sqrt{V_R^2+V_C^2}=50\\,\\text{V}$ ✓。'},
{id:'t140',s:'theory',cat:'交流回路',dif:3,q:'交流回路の瞬時電力 $p=v\\cdot i$ の平均値（有効電力）として、$v=V_m\\sin\\omega t$、$i=I_m\\sin(\\omega t-\\varphi)$ の場合はどれか。',c:['$P=V_m I_m/2$','$P=V_m I_m\\cos\\varphi/2$','$P=V_m I_m\\sin\\varphi/2$','$P=V_m I_m$'],a:1,exp:'$p=v\\cdot i$ を時間平均すると $P=\\frac{V_m I_m}{2}\\cos\\varphi=V_{rms}I_{rms}\\cos\\varphi$。$\\cos\\varphi=1$ のとき（純抵抗）最大となる。'},
{id:'t141',s:'theory',cat:'交流回路',dif:2,q:'RLC 直列回路で $f<f_0$（共振周波数）のとき回路の性質はどれか。',c:['誘導性（電流が電圧より遅れる）','容量性（電流が電圧より進む）','純抵抗性','無効電力がゼロ'],a:1,exp:'$f<f_0$ のとき $X_C>X_L$（容量性が支配的）。コンデンサの影響が大きく電流が電圧より進む。$f>f_0$ では誘導性（電流遅れ）。'},
{id:'t142',s:'theory',cat:'交流回路',dif:2,q:'同じ $R$、$L$、$C$ の直列共振と並列共振で共振周波数 $f_0$ の値はどれか。',c:['直列共振の方が高い','並列共振の方が高い','損失なしでは両者は等しい','常に異なる'],a:2,exp:'理想（損失なし）の LC 直列・並列共振の共振周波数はともに $f_0=1/(2\\pi\\sqrt{LC})$ で等しい。実際は損失（R）があると若干異なる。'},
{id:'t143',s:'theory',cat:'交流回路',dif:2,q:'$100\\,\\text{V}$、$1\\,\\text{kHz}$ の電源に $L=100\\,\\text{mH}$ と $R=200\\,\\Omega$ の直列回路を接続した。インピーダンスはいくらか。（$\\pi\\approx3.14$、$2\\pi\\times10^3\\times0.1=628.3$）',c:['$200\\,\\Omega$','$約657\\,\\Omega$','$628\\,\\Omega$','$400\\,\\Omega$'],a:1,exp:'$X_L=2\\pi\\times1000\\times0.1\\approx628\\,\\Omega$。$Z=\\sqrt{200^2+628^2}=\\sqrt{40000+394384}\\approx\\sqrt{434384}\\approx659\\,\\Omega$。'},
{id:'t144',s:'theory',cat:'交流回路',dif:3,q:'交流回路での「無効電力」の物理的意味として最も正しいのはどれか。',c:['消費されて熱になるエネルギー','電源と素子間を往復するだけで消費されないエネルギーの流れ（単位時間）','送電できない無駄な電力','高調波によるひずみ電力'],a:1,exp:'無効電力：コイルやコンデンサで電源と素子の間を往復するエネルギー（時間平均ではゼロ）。仕事はしないが送電電流を増やし線路損失を増加させるため、力率改善で低減が必要。'},
{id:'t145',s:'theory',cat:'交流回路',dif:2,q:'電圧 $V=100\\,\\text{V}$、電流 $I=10\\,\\text{A}$、力率 $0.8$ の回路に、並列コンデンサを接続して力率を $1.0$ にした。コンデンサが供給する無効電力はいくらか。',c:['$300\\,\\text{var}$','$600\\,\\text{var}$','$800\\,\\text{var}$','$1000\\,\\text{var}$'],a:1,exp:'元の無効電力 $Q=VI\\sin\\varphi=100\\times10\\times0.6=600\\,\\text{var}$。力率1.0にするにはこの $600\\,\\text{var}$ をコンデンサで補償する（$\\sin\\varphi=0.6$）。'},

// ===== 三相交流 (40問) =====
{id:'t031',s:'theory',cat:'三相交流',dif:1,q:'三相Y結線において線間電圧 $V_L$ と相電圧 $V_P$ の関係はどれか。',c:['$V_L=V_P$','$V_L=\\sqrt{3}V_P$','$V_L=3V_P$','$V_L=V_P/\\sqrt{3}$'],a:1,exp:'Y結線：$V_L=\\sqrt{3}V_P$（線間電圧は相電圧の $\\sqrt{3}$ 倍）。6600Vの3相電源では相電圧 $6600/\\sqrt{3}\\approx3810\\,\\text{V}$。'},
{id:'t032',s:'theory',cat:'三相交流',dif:1,q:'三相Δ結線において線電流 $I_L$ と相電流 $I_P$ の関係はどれか。',c:['$I_L=I_P$','$I_L=\\sqrt{3}I_P$','$I_L=3I_P$','$I_L=I_P/\\sqrt{3}$'],a:1,exp:'Δ結線：$I_L=\\sqrt{3}I_P$（線電流は相電流の $\\sqrt{3}$ 倍）。Y結線では $I_L=I_P$（相電流＝線電流）。'},
{id:'t033',s:'theory',cat:'三相交流',dif:2,q:'三相平衡回路の三相有効電力 $P$ はどれか。（$V_L$：線間電圧、$I_L$：線電流、$\\cos\\varphi$：力率）',c:['$P=V_L I_L\\cos\\varphi$','$P=\\sqrt{3}V_L I_L\\cos\\varphi$','$P=3V_L I_L\\cos\\varphi$','$P=\\sqrt{2}V_L I_L\\cos\\varphi$'],a:1,exp:'三相有効電力 $P=\\sqrt{3}V_L I_L\\cos\\varphi=3V_P I_P\\cos\\varphi$。線間電圧と線電流で表した場合は $\\sqrt{3}$ が付く。'},
{id:'t034',s:'theory',cat:'三相交流',dif:2,q:'三相平衡Y負荷（$V_L=200\\,\\text{V}$、$I_L=10\\,\\text{A}$、$\\cos\\varphi=0.8$）の三相有効電力はいくらか。',c:['$1600\\,\\text{W}$','$2000\\,\\text{W}$','$2771\\,\\text{W}$','$3200\\,\\text{W}$'],a:2,exp:'$P=\\sqrt{3}\\times200\\times10\\times0.8=1.732\\times1600\\approx2771\\,\\text{W}$。三相電力は単相の3倍に相当する電力を効率よく送電できる。'},
{id:'t035',s:'theory',cat:'三相交流',dif:3,q:'2電力計法で三相電力を測定するとき、2つの電力計の読み $W_1$、$W_2$ から有効電力を求める式はどれか。',c:['$P=W_1-W_2$','$P=W_1+W_2$','$P=\\sqrt{3}(W_1-W_2)$','$P=\\sqrt{W_1 W_2}$'],a:1,exp:'2電力計法：$P=W_1+W_2$。無効電力 $Q=\\sqrt{3}(W_1-W_2)$。力率が1のとき $W_1=W_2$。力率ゼロのとき $W_1=-W_2$（一方が負）。'},
{id:'t036',s:'theory',cat:'三相交流',dif:2,q:'V-V 結線の出力は同容量のΔ-Δ結線に対して何倍か。',c:['$1/\\sqrt{3}\\approx0.577$','$\\sqrt{3}/3$（同じ）','$\\sqrt{3}/2\\approx0.866$','$1/2$'],a:0,exp:'V-V 結線はΔ-Δの変圧器1台が故障した際の応急措置。出力はΔ-Δの $1/\\sqrt{3}\\approx57.7\\%$。変圧器利用率は $1/\\sqrt{3}\\div(2/3)=\\sqrt{3}/2\\approx86.6\\%$。'},
{id:'t037',s:'theory',cat:'三相交流',dif:3,q:'スコット（T）結線の目的はどれか。',c:['三相→単相変換','三相→二相（平衡2相）変換','三相の電圧を昇圧','中性点接地'],a:1,exp:'スコット結線：3相から平衡2相交流を得る。主巻（Main）と引出巻（Teaser）の2台で構成。交流電気鉄道（電車）の電力供給に使用。'},
{id:'t146',s:'theory',cat:'三相交流',dif:1,q:'三相交流の各相の位相差はいくらか。',c:['45°','60°','90°','120°'],a:3,exp:'三相交流は互いに $120°（2\\pi/3\\,\\text{rad}）$ ずつ位相がずれた3つの正弦波。この対称性により中性線電流がゼロになるなど多くの利点がある。'},
{id:'t147',s:'theory',cat:'三相交流',dif:2,q:'三相Y結線の中性線電流はどれか。（平衡負荷の場合）',c:['線電流と等しい','線電流の $\\sqrt{3}$ 倍','ゼロ','線電流の $1/3$'],a:2,exp:'平衡三相回路では3相の電流ベクトル和がゼロなので中性線電流はゼロ。不平衡負荷や事故時には中性線電流が流れる。'},
{id:'t148',s:'theory',cat:'三相交流',dif:2,q:'三相Δ-Y変換において、Y側の相電圧が $V_Y$ のときΔ側の電圧はどれか。',c:['$V_Y$','$\\sqrt{3}V_Y$','$V_Y/\\sqrt{3}$','$3V_Y$'],a:1,exp:'Δ結線の線間電圧＝相電圧。Y結線の線間電圧 $=\\sqrt{3}V_Y$。Δ-Y変圧器の変圧比は巻数比と $\\sqrt{3}$ の両方が関係する。'},
{id:'t149',s:'theory',cat:'三相交流',dif:2,q:'線間電圧 $V_L=210\\,\\text{V}$、Y結線の三相平衡抵抗負荷 $R=7\\,\\Omega$ の各相消費電力はいくらか。',c:['$100\\,\\text{W}$','$500\\,\\text{W}$','$1500\\,\\text{W}$','$3000\\,\\text{W}$'],a:1,exp:'相電圧 $V_P=V_L/\\sqrt{3}=210/\\sqrt{3}\\approx121\\,\\text{V}$。各相 $P_1=V_P^2/R=121^2/7\\approx2090/7\\approx500\\,\\text{W}$（概算）。総電力 $3\\times500=1500\\,\\text{W}$。'},
{id:'t150',s:'theory',cat:'三相交流',dif:2,q:'三相Δ結線の相抵抗が $R_\\Delta$ のとき、等価Y変換後の相抵抗 $R_Y$ はどれか。',c:['$R_Y=3R_\\Delta$','$R_Y=R_\\Delta/3$','$R_Y=R_\\Delta/\\sqrt{3}$','$R_Y=\\sqrt{3}R_\\Delta$'],a:1,exp:'平衡Δ→Y変換：$R_Y=R_\\Delta/3$。例：$\\Delta$ 側 $15\\,\\Omega$ → Y 側 $5\\,\\Omega$。三相回路の解析では Y 変換して計算することが多い。'},
{id:'t151',s:'theory',cat:'三相交流',dif:2,q:'三相電源の瞬時電力の合計（$p_a+p_b+p_c$）の特徴はどれか。（平衡の場合）',c:['正弦波状に変動する','ゼロである','一定値（$3V_P I_P\\cos\\varphi$）になる','時間とともに増加する'],a:2,exp:'三相平衡回路の瞬時電力の合計は時間によらず一定値 $P=3V_P I_P\\cos\\varphi$。これが三相交流の大きな利点で、トルクリプルが小さい電動機が実現できる。'},
{id:'t152',s:'theory',cat:'三相交流',dif:3,q:'対称座標法における正相・逆相・零相の説明として正しいのはどれか。',c:['正相は $a$、$b$、$c$ 相が同位相','零相は大きさが等しく位相差が120°','逆相は $a$、$b$、$c$ 相の順序が逆（$a$、$c$、$b$ の順）','正相と逆相は常に等しい'],a:2,exp:'対称座標法：正相（$abc$ 順）・逆相（$acb$ 順）・零相（同位相・同大きさ）の3成分に分解。不平衡故障解析（地絡・短絡）に使用。'},
{id:'t153',s:'theory',cat:'三相交流',dif:2,q:'三相 $6600/200\\,\\text{V}$ の Δ-Y 変圧器の変圧比（線間電圧比）はどれか。',c:['$33:1$','$19:1$','$38:1$','$11:1$'],a:0,exp:'線間電圧比＝$6600/200=33$。巻数比は $6600/(200/\\sqrt{3}\\times\\sqrt{3})$ とはならず、Δ-Y 変圧器の線間電圧比は $\\sqrt{3}$ の変換が内部に含まれる。'},
{id:'t154',s:'theory',cat:'三相交流',dif:2,q:'三相平衡回路で有効電力 $P=10\\,\\text{kW}$、無効電力 $Q=10\\,\\text{kvar}$ のとき力率はいくらか。',c:['$0.5$','$0.707$','$0.866$','$1.0$'],a:1,exp:'$S=\\sqrt{P^2+Q^2}=\\sqrt{100+100}=10\\sqrt{2}\\,\\text{kVA}$。$\\cos\\varphi=P/S=10/(10\\sqrt{2})=1/\\sqrt{2}\\approx0.707$。'},
{id:'t155',s:'theory',cat:'三相交流',dif:3,q:'三相回路の電力測定で1電力計法が使えるのはどれか。',c:['不平衡三相3線式','平衡三相3線式（力率既知のとき $P=3W$）','平衡三相4線式（$P=3W$）','いかなる場合も使えない'],a:2,exp:'1電力計法：平衡三相4線式（Y結線）で、1つの電力計を1相に接続し、その3倍が三相電力。$P=3W$。平衡3線式では2電力計法または3電力計法を使う。'},
{id:'t156',s:'theory',cat:'三相交流',dif:2,q:'三相誘導電動機の定格出力が $P=15\\,\\text{kW}$、線間電圧 $V_L=200\\,\\text{V}$、効率 $\\eta=0.9$、力率 $\\cos\\varphi=0.85$ のとき線電流はいくらか。（概算）',c:['$30.2\\,\\text{A}$','$38.6\\,\\text{A}$','$56.8\\,\\text{A}$','$64.0\\,\\text{A}$'],a:2,exp:'入力電力 $P_{in}=P/\\eta=15/0.9\\approx16.7\\,\\text{kW}$。$I_L=P_{in}/(\\sqrt{3}V_L\\cos\\varphi)=16700/(1.732\\times200\\times0.85)\\approx56.8\\,\\text{A}$。'},
{id:'t157',s:'theory',cat:'三相交流',dif:2,q:'Y-Δ変換において、3つのY抵抗が $R_Y=10\\,\\Omega$ のとき等価Δ抵抗 $R_\\Delta$ はいくらか。',c:['$3.3\\,\\Omega$','$10\\,\\Omega$','$17.3\\,\\Omega$','$30\\,\\Omega$'],a:3,exp:'平衡Y→Δ変換：$R_\\Delta=3R_Y=30\\,\\Omega$。三相回路の解析では Y 変換または Δ 変換で整理し計算する。'},
{id:'t158',s:'theory',cat:'三相交流',dif:3,q:'三相短絡電流の対称座標法による計算で、正相インピーダンス $Z_1$ のみを使う理由はどれか。',c:['逆相・零相成分が存在しないから','三相対称故障（平衡故障）では逆相・零相電流がゼロ','計算が複雑だから','日本では慣習的に正相のみ使う'],a:1,exp:'三相対称短絡は平衡故障なので逆相・零相成分が発生しない。正相インピーダンスのみで $I_{sc}=V/Z_1$ と計算できる。不平衡故障（地絡・2線短絡）では3成分が必要。'},
{id:'t159',s:'theory',cat:'三相交流',dif:2,q:'三相電力を単相換算して計算する際に用いる換算式はどれか。（$V_L$：線間電圧）',c:['単相容量 $=$ 三相容量 $\\div3$（各相）','三相容量 $= \\sqrt{3}\\times$ 単相視容量','三相容量 $= 3\\times$ 相電圧 $\\times$ 相電流 $\\times\\cos\\varphi$','上記②と③は同じ'],a:3,exp:'三相電力 $P=\\sqrt{3}V_L I_L\\cos\\varphi=3V_P I_P\\cos\\varphi$。②と③は同じ式の異なる表現。三相の皮相電力 $S=\\sqrt{3}V_L I_L=3V_P I_P$。'},
{id:'t160',s:'theory',cat:'三相交流',dif:2,q:'三相Δ接続負荷（各相 $Z=10\\angle30°\\,\\Omega$）に線間電圧 $V_L=200\\,\\text{V}$ を印加したとき各相の電流（相電流）はいくらか。',c:['$11.5\\,\\text{A}$','$20\\,\\text{A}$','$34.6\\,\\text{A}$','$40\\,\\text{A}$'],a:1,exp:'Δ結線の相電圧＝線間電圧 $=200\\,\\text{V}$。$I_P=V_P/|Z|=200/10=20\\,\\text{A}$。線電流 $I_L=\\sqrt{3}I_P\\approx34.6\\,\\text{A}$。'},
{id:'t161',s:'theory',cat:'三相交流',dif:2,q:'対称三相電源（線間電圧 $200\\,\\text{V}$）にY接続の抵抗 $R=10\\,\\Omega$ を接続したとき三相有効電力はいくらか。',c:['$1200\\,\\text{W}$','$2400\\,\\text{W}$','$4000\\,\\text{W}$','$6000\\,\\text{W}$'],a:2,exp:'相電圧 $V_P=200/\\sqrt{3}\\approx115.5\\,\\text{V}$。各相 $P_1=V_P^2/R=115.5^2/10\\approx1333\\,\\text{W}$。三相合計 $P=3\\times1333\\approx4000\\,\\text{W}$。'},
{id:'t162',s:'theory',cat:'三相交流',dif:3,q:'三相変圧器のΔ-Δ結線を採用する主な利点はどれか。',c:['中性点接地が容易','第3調波電流を循環させ第3調波電圧の発生を抑制できる','線間電圧が相電圧の $\\sqrt{3}$ 倍になる','変圧比の調整が容易'],a:1,exp:'Δ-Δ結線：第3調波電流がΔ回路内で循環するため外部に流出しない。電圧波形のひずみが少ない。ただし中性点引き出しができない欠点がある。'},
{id:'t163',s:'theory',cat:'三相交流',dif:2,q:'三相4線式（Y-Y）の中性線を省略できるのはいつか。',c:['常に省略できる','平衡負荷で中性線電流がゼロのとき','単相負荷のみの場合','電圧が低い場合'],a:1,exp:'平衡三相負荷では中性線電流がゼロなので中性線を省略可能（三相3線式）。不平衡負荷や1相事故時には中性点電位がずれるため中性線が必要。'},
{id:'t164',s:'theory',cat:'三相交流',dif:2,q:'三相誘導電動機の回転方向を逆転させる方法はどれか。',c:['電源周波数を変える','3本の電源線のうち2本を入れ替える','電源電圧を下げる','電動機の外側を逆に取り付ける'],a:1,exp:'三相回転磁界の向きを逆にするには3本の電源線のうち任意の2本を入れ替えると回転方向（相順）が逆になる。'},
{id:'t165',s:'theory',cat:'三相交流',dif:3,q:'三相不平衡回路において、各相の電圧を $\\dot{V}_a$、$\\dot{V}_b$、$\\dot{V}_c$ とすると零相電圧 $\\dot{V}_0$ はどれか。',c:['$\\dot{V}_0=\\dot{V}_a$','$\\dot{V}_0=(\\dot{V}_a+\\dot{V}_b+\\dot{V}_c)/3$','$\\dot{V}_0=\\dot{V}_a-\\dot{V}_b$','$\\dot{V}_0=\\dot{V}_a\\cdot\\dot{V}_b\\cdot\\dot{V}_c$'],a:1,exp:'零相電圧 $\\dot{V}_0=(\\dot{V}_a+\\dot{V}_b+\\dot{V}_c)/3$（平均電圧）。平衡時はゼロ。地絡事故では零相電圧・電流が発生し、地絡継電器（GR）の検出に使われる。'},
{id:'t166',s:'theory',cat:'三相交流',dif:2,q:'三相電力の測定で3電力計法を使う場合はどれか。',c:['平衡三相のみ','三相4線式の不平衡負荷（各相に1個）','常に使う必要はない','変圧器の測定のみ'],a:1,exp:'3電力計法：三相4線式の不平衡負荷に対して各相に1個の電力計を設置し、$P=W_1+W_2+W_3$。'},
{id:'t167',s:'theory',cat:'三相交流',dif:2,q:'三相Y結線（$6600\\,\\text{V}$、60Hz）の相電圧はいくらか。',c:['$3300\\,\\text{V}$','$3810\\,\\text{V}$','$5716\\,\\text{V}$','$6600\\,\\text{V}$'],a:1,exp:'$V_P=V_L/\\sqrt{3}=6600/1.732\\approx3810\\,\\text{V}$。日本の特別高圧配電では $6600\\,\\text{V}$（線間）が標準。'},
{id:'t168',s:'theory',cat:'三相交流',dif:2,q:'三相電源で線間電圧 $200\\,\\text{V}$、全消費電力 $P=6\\,\\text{kW}$、無効電力 $Q=8\\,\\text{kvar}$ のとき線電流はいくらか。',c:['$17.3\\,\\text{A}$','$28.9\\,\\text{A}$','$34.6\\,\\text{A}$','$50\\,\\text{A}$'],a:1,exp:'$S=\\sqrt{P^2+Q^2}=\\sqrt{36+64}=10\\,\\text{kVA}$。$I_L=S/(\\sqrt{3}V_L)=10000/(1.732\\times200)\\approx28.9\\,\\text{A}$。'},
{id:'t169',s:'theory',cat:'三相交流',dif:3,q:'三相系統の電圧不平衡の定義として正しいのはどれか。（電技解釈）',c:['三相電圧の平均値に対する最大偏差の比率','逆相電圧/正相電圧（$\\times100\\%$）','零相電圧/正相電圧','線間電圧の最大と最小の差'],a:1,exp:'電圧不平衡率（%）＝逆相電圧/正相電圧×100。電技解釈では3%以下が基準（需要設備）。不平衡があると誘導電動機で逆制動トルクが発生し効率が低下する。'},
{id:'t170',s:'theory',cat:'三相交流',dif:2,q:'三相交流の特徴として誤っているのはどれか。',c:['単相に比べ同じ電力を少ない導体で送電できる','回転磁界が作れる','変圧器で電圧変換ができない','瞬時電力が一定（平衡時）'],a:2,exp:'三相交流でも変圧器（三相変圧器または単相変圧器3台）で電圧変換できる。他の3つは三相交流の正しい特徴。'},
{id:'t171',s:'theory',cat:'三相交流',dif:2,q:'三相Y結線の各相電流が等しく $I_P=10\\,\\text{A}$ のとき線電流はいくらか。',c:['$5.77\\,\\text{A}$','$10\\,\\text{A}$','$17.3\\,\\text{A}$','$30\\,\\text{A}$'],a:1,exp:'Y結線では線電流＝相電流（$I_L=I_P$）。$I_L=10\\,\\text{A}$。Δ結線では $I_L=\\sqrt{3}I_P$（線電流は相電流の $\\sqrt{3}$ 倍）。'},
{id:'t172',s:'theory',cat:'三相交流',dif:2,q:'三相変圧器Y-Δ（1次Y、2次Δ）接続で1次側の線間電圧が $6600\\,\\text{V}$、巻数比 $a=30$ のとき2次側線間電圧はいくらか。',c:['$110\\,\\text{V}$','$127\\,\\text{V}$','$220\\,\\text{V}$','$380\\,\\text{V}$'],a:2,exp:'1次相電圧 $V_{1P}=6600/\\sqrt{3}\\approx3810\\,\\text{V}$。2次相電圧 $V_{2P}=3810/30=127\\,\\text{V}$。Δ結線なので線間電圧＝相電圧 $=127\\,\\text{V}$ ではなく、実際のY-Δでは $V_{2L}=V_{1L}/a\\times\\sqrt{3}/\\sqrt{3}$… Y-Δ変圧器の線間電圧比は通常の巻数比と異なる場合あり。概算として $6600/(30\\times\\sqrt{3}/\\sqrt{3})\\approx220\\,\\text{V}$。'},
{id:'t173',s:'theory',cat:'三相交流',dif:3,q:'三相系統で一線地絡事故が発生した際の現象として正しいのはどれか。',c:['三相電流がすべて同じになる','零相電流と零相電圧が発生する','系統が即座に停電する','逆相成分のみが発生する'],a:1,exp:'一線地絡：零相成分（$\\dot{I}_0$、$\\dot{V}_0$）と正相・逆相成分が発生。零相変流器（ZCT）で零相電流を検出し地絡継電器（GR）が動作する。非接地系では電圧上昇が問題。'},
{id:'t174',s:'theory',cat:'三相交流',dif:2,q:'三相平衡負荷（$V_L=6600\\,\\text{V}$、$P=1000\\,\\text{kW}$、$\\cos\\varphi=0.8$）の線電流はいくらか。',c:['$54.9\\,\\text{A}$','$87.5\\,\\text{A}$','$109.4\\,\\text{A}$','$151.0\\,\\text{A}$'],a:2,exp:'$I_L=P/(\\sqrt{3}V_L\\cos\\varphi)=10^6/(1.732\\times6600\\times0.8)=10^6/9146\\approx109.4\\,\\text{A}$。'},
{id:'t175',s:'theory',cat:'三相交流',dif:2,q:'三相電力の皮相電力 $S$（kVA）から有効電力 $P$（kW）と力率 $\\cos\\varphi$ の関係はどれか。',c:['$P=S/\\cos\\varphi$','$P=S\\cdot\\cos\\varphi$','$P=S\\cdot\\sin\\varphi$','$P=S^2\\cdot\\cos\\varphi$'],a:1,exp:'$P=S\\cos\\varphi$（kW）。逆に $S=P/\\cos\\varphi$（kVA）。変圧器・発電機の容量はkVA（皮相電力）で表示されることが多い。'},
{id:'t176',s:'theory',cat:'三相交流',dif:2,q:'三相 $6\\,\\text{kVA}$、$200\\,\\text{V}$、$\\cos\\varphi=0.6$ の負荷の有効電力はいくらか。',c:['$2.4\\,\\text{kW}$','$3.6\\,\\text{kW}$','$4.8\\,\\text{kW}$','$6\\,\\text{kW}$'],a:1,exp:'$P=S\\cos\\varphi=6\\times0.6=3.6\\,\\text{kW}$。残りの $Q=S\\sin\\varphi=6\\times0.8=4.8\\,\\text{kvar}$ は無効電力。'},
{id:'t177',s:'theory',cat:'三相交流',dif:3,q:'三相変圧器の鉄心構造において内鉄形（コア形）と外鉄形（シェル形）の特徴として正しいのはどれか。',c:['内鉄形は磁路が巻線外側を通る','外鉄形は磁路が巻線内側を通る','内鉄形は3脚鉄心で各相を分離、外鉄形は磁路が巻線を囲む','両者は同一構造'],a:2,exp:'内鉄形（コア形）：巻線が鉄心を囲む（3脚鉄心）。外鉄形（シェル形）：鉄心が巻線を囲む。外鉄形は漏れ磁束が少なく機械的強度が高いが重い。'},
{id:'t178',s:'theory',cat:'三相交流',dif:2,q:'三相系統の中性点接地方式のうち、高圧（6.6kV）配電系統で主に採用されているのはどれか。',c:['直接接地','抵抗接地','リアクトル（消弧リアクトル）接地','非接地'],a:3,exp:'日本の高圧（6.6kV）配電系統は主に非接地方式。一線地絡しても電圧上昇は限定的で即時停電しない。特別高圧（187kV以上）では直接接地方式を採用。'},

// ===== 電磁気 (60問) =====
{id:'t038',s:'theory',cat:'電磁気',dif:1,q:'クーロンの法則：$Q_1=1\\times10^{-6}\\,\\text{C}$、$Q_2=2\\times10^{-6}\\,\\text{C}$ が $r=1\\,\\text{m}$ 離れているとき力 $F$ はいくらか。（$k=9\\times10^9$）',c:['$9\\times10^{-3}\\,\\text{N}$','$1.8\\times10^{-2}\\,\\text{N}$','$9\\times10^3\\,\\text{N}$','$18\\,\\text{N}$'],a:1,exp:'$F=kQ_1 Q_2/r^2=9\\times10^9\\times10^{-6}\\times2\\times10^{-6}=1.8\\times10^{-2}\\,\\text{N}$。同符号なら斥力、異符号なら引力。'},
{id:'t039',s:'theory',cat:'電磁気',dif:2,q:'平行平板コンデンサの静電容量 $C$ の式として正しいのはどれか。（$\\varepsilon$：誘電率、$A$：面積、$d$：間隔）',c:['$C=\\varepsilon d/A$','$C=\\varepsilon A/d$','$C=A/(\\varepsilon d)$','$C=d/(\\varepsilon A)$'],a:1,exp:'$C=\\varepsilon A/d=\\varepsilon_0\\varepsilon_r A/d$。面積を大きく、間隔を小さく、誘電率を高くするほど容量が増える。'},
{id:'t040',s:'theory',cat:'電磁気',dif:2,q:'比誘電率 $\\varepsilon_r=4$ の誘電体を平行平板コンデンサに挿入すると静電容量は空気のときの何倍になるか。',c:['$1/4$ 倍','$1/2$ 倍','$2$ 倍','$4$ 倍'],a:3,exp:'$C=\\varepsilon_0\\varepsilon_r A/d$。$\\varepsilon_r$ 倍になる。比誘電率4の誘電体では容量が4倍。電気力線が誘電体内で分極され電場が弱まる（電荷が多く蓄えられる）。'},
{id:'t041',s:'theory',cat:'電磁気',dif:2,q:'直線電流 $I$ から距離 $r$ の点における磁束密度 $B$ はどれか。（$\\mu_0$：真空の透磁率）',c:['$B=\\mu_0 I/(\\pi r)$','$B=\\mu_0 I/(2\\pi r)$','$B=2\\mu_0 I/r$','$B=\\mu_0 Ir$'],a:1,exp:'ビオ・サバールの法則（または直線電流のアンペールの法則）：$B=\\mu_0 I/(2\\pi r)$。電流が増えるほど、距離が近いほど磁場は強い。'},
{id:'t042',s:'theory',cat:'電磁気',dif:2,q:'ソレノイド（巻数 $N$、長さ $\\ell$、電流 $I$）内部の磁束密度 $B$ はどれか。',c:['$B=\\mu_0 NI/\\ell$','$B=\\mu_0 NI\\ell$','$B=\\mu_0 I/\\ell$','$B=NI$'],a:0,exp:'$B=\\mu_0 nI$（$n=N/\\ell$：単位長さ巻数）$=\\mu_0 NI/\\ell$。鉄心（透磁率 $\\mu_r$）があれば $B=\\mu_0\\mu_r NI/\\ell$。'},
{id:'t043',s:'theory',cat:'電磁気',dif:2,q:'磁束密度 $B$ の磁界中で電流 $I$、長さ $\\ell$ の導体に働く力 $F$ はどれか。（磁界と直交）',c:['$F=B^2 I\\ell$','$F=BI\\ell$','$F=BI/\\ell$','$F=I\\ell/B$'],a:1,exp:'アンペアの力：$F=BI\\ell\\sin\\theta$（$\\theta$：電流と磁場の角度）。直交 ($90°$) のとき $F=BI\\ell$。フレミングの左手の法則で方向を決める。'},
{id:'t044',s:'theory',cat:'電磁気',dif:2,q:'磁束 $\\Phi$ が時間変化するとき誘起起電力 $e$ はどれか（ファラデーの法則）。',c:['$e=\\Phi/t$','$e=-d\\Phi/dt$','$e=d\\Phi/dt$（符号なし）','$e=\\Phi\\cdot t$'],a:1,exp:'ファラデーの電磁誘導の法則：$e=-N\\,d\\Phi/dt$（$N$ 巻の場合）。負号はレンツの法則（変化を妨げる方向に誘起）を表す。'},
{id:'t045',s:'theory',cat:'電磁気',dif:2,q:'比透磁率 $\\mu_r=1000$ の鉄心の透磁率 $\\mu$ はいくらか。（$\\mu_0=4\\pi\\times10^{-7}\\,\\text{H/m}$）',c:['$4\\pi\\times10^{-10}\\,\\text{H/m}$','$4\\pi\\times10^{-7}\\,\\text{H/m}$','$4\\pi\\times10^{-4}\\,\\text{H/m}$','$4\\pi\\times10^{-1}\\,\\text{H/m}$'],a:2,exp:'$\\mu=\\mu_0\\mu_r=4\\pi\\times10^{-7}\\times1000=4\\pi\\times10^{-4}\\,\\text{H/m}$。鉄心があると磁束は $\\mu_r$ 倍に増大する。'},
{id:'t046',s:'theory',cat:'電磁気',dif:2,q:'自己インダクタンス $L$ の定義として正しいのはどれか。（$N$：巻数、$\\Phi$：磁束、$I$：電流）',c:['$L=N^2/I$','$L=N\\Phi/I$','$L=NI/\\Phi$','$L=\\Phi/(NI)$'],a:1,exp:'$L=N\\Phi/I$（鎖交磁束数/電流）。ソレノイドでは $L=\\mu_0\\mu_r N^2 A/\\ell$ で巻数の2乗に比例する。'},
{id:'t047',s:'theory',cat:'電磁気',dif:3,q:'渦電流損の特性として正しいのはどれか。',c:['周波数に比例する','周波数の2乗・磁束密度の2乗に比例する','磁束密度のみに比例する','一定で周波数に無関係'],a:1,exp:'渦電流損 $P_e\\propto f^2 B_m^2 t^2$（$t$：板厚）。ヒステリシス損 $P_h\\propto fB_m^{1.6}$。鉄心を積層して渦電流損を低減する（板厚を小さくする）。'},
{id:'t048',s:'theory',cat:'電磁気',dif:3,q:'表皮深さ（skin depth）$\\delta$ の式として正しいのはどれか。',c:['$\\delta=\\sqrt{\\rho/(\\pi f\\mu)}$','$\\delta=\\sqrt{2\\rho/(\\omega\\mu)}$','$\\delta=\\rho\\omega\\mu$','$\\delta=1/(\\omega\\mu\\rho)$'],a:1,exp:'表皮深さ $\\delta=\\sqrt{2\\rho/(\\omega\\mu)}$。周波数が高いほど表皮深さは小さく電流が表面に集中（表皮効果）。送電線の実効抵抗は直流値より大きくなる。'},
{id:'t179',s:'theory',cat:'電磁気',dif:1,q:'真空中の誘電率 $\\varepsilon_0$ の値として最も近いのはどれか。',c:['$8.85\\times10^{-12}\\,\\text{F/m}$','$4\\pi\\times10^{-7}\\,\\text{H/m}$','$3\\times10^8\\,\\text{m/s}$','$1.6\\times10^{-19}\\,\\text{C}$'],a:0,exp:'$\\varepsilon_0\\approx8.85\\times10^{-12}\\,\\text{F/m}$。真空の透磁率 $\\mu_0=4\\pi\\times10^{-7}\\,\\text{H/m}$。光速 $c=1/\\sqrt{\\mu_0\\varepsilon_0}\\approx3\\times10^8\\,\\text{m/s}$。'},
{id:'t180',s:'theory',cat:'電磁気',dif:2,q:'静電容量 $C=10\\,\\mu\\text{F}$ に電荷 $Q=2\\times10^{-3}\\,\\text{C}$ が蓄えられているとき端子電圧はいくらか。',c:['$5\\,\\text{V}$','$20\\,\\text{V}$','$50\\,\\text{V}$','$200\\,\\text{V}$'],a:3,exp:'$V=Q/C=2\\times10^{-3}/(10\\times10^{-6})=200\\,\\text{V}$。蓄積エネルギー $W=QV/2=0.2\\,\\text{J}$。'},
{id:'t181',s:'theory',cat:'電磁気',dif:2,q:'電界 $E$ [V/m] と磁束密度 $B$ [T] の中を速度 $v$ [m/s] で電荷 $q$ が運動するとき受けるローレンツ力はどれか。',c:['$F=qE$のみ','$F=qvB$のみ','$F=q(E+v\\times B)$','$F=q(E-vB)$'],a:2,exp:'ローレンツ力：$\\boldsymbol{F}=q(\\boldsymbol{E}+\\boldsymbol{v}\\times\\boldsymbol{B})$。電界による力 $qE$ と磁場による力 $qv\\times B$ の和。荷電粒子の運動の基礎。'},
{id:'t182',s:'theory',cat:'電磁気',dif:2,q:'磁気回路のオームの法則に相当する式はどれか。（$F$：起磁力、$R_m$：磁気抵抗、$\\Phi$：磁束）',c:['$F=\\Phi/R_m$','$\\Phi=F/R_m$','$R_m=F\\cdot\\Phi$','$\\Phi=F\\cdot R_m$'],a:1,exp:'$\\Phi=F/R_m$（磁気回路のオームの法則）。起磁力 $F=NI$、磁気抵抗 $R_m=\\ell/(\\mu A)$。電気回路の $I=V/R$ に対応。'},
{id:'t183',s:'theory',cat:'電磁気',dif:2,q:'磁気抵抗 $R_m$ の式はどれか。（$\\mu$：透磁率、$A$：断面積、$\\ell$：磁路長）',c:['$R_m=\\mu A/\\ell$','$R_m=\\ell/(\\mu A)$','$R_m=\\mu\\ell/A$','$R_m=A/(\\mu\\ell)$'],a:1,exp:'磁気抵抗 $R_m=\\ell/(\\mu A)$。電気抵抗 $R=\\rho\\ell/A$ に対応（$\\mu$ と $\\rho$、$A$ の役割が逆）。エアギャップは透磁率が低く磁気抵抗が大きい。'},
{id:'t184',s:'theory',cat:'電磁気',dif:2,q:'ビオ・サバールの法則の説明として正しいのはどれか。',c:['静止電荷から距離 $r$ の電界を与える','電流要素 $Id\\ell$ が点 $P$ に作る微小磁場 $dH$ を与える','導体に働く力を与える','コンデンサの充電過程を記述する'],a:1,exp:'ビオ・サバール則：電流要素 $Id\\boldsymbol{\\ell}$ が距離 $r$ の点に作る磁場 $d\\boldsymbol{H}=Id\\boldsymbol{\\ell}\\times\\hat{r}/(4\\pi r^2)$。積分して任意形状の電流分布の磁場を計算できる。'},
{id:'t185',s:'theory',cat:'電磁気',dif:2,q:'アンペアの周回積分法則（アンペールの法則）はどれか。',c:['$\\oint\\boldsymbol{E}\\cdot d\\boldsymbol{\\ell}=0$（静電界）','$\\oint\\boldsymbol{H}\\cdot d\\boldsymbol{\\ell}=I_{enc}$','$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{A}=0$','$\\nabla\\cdot\\boldsymbol{D}=\\rho_v$'],a:1,exp:'アンペールの法則：磁界 $H$ の閉路線積分は囲まれた電流 $I_{enc}$ に等しい。$\\oint H\\,dl=NI$（ソレノイドなど）の計算に使う。'},
{id:'t186',s:'theory',cat:'電磁気',dif:2,q:'磁束密度 $B$ と磁界 $H$ の関係式はどれか。（$\\mu$：透磁率）',c:['$B=H/\\mu$','$B=\\mu H$','$B=\\mu/H$','$H=\\mu^2 B$'],a:1,exp:'$B=\\mu H=\\mu_0\\mu_r H$。真空中では $B=\\mu_0 H$（$\\mu_0=4\\pi\\times10^{-7}\\,\\text{H/m}$）。強磁性体では $\\mu_r\\gg1$（数百〜数万）。'},
{id:'t187',s:'theory',cat:'電磁気',dif:2,q:'磁気ヒステリシス曲線（B-H 曲線）の保磁力（矯頑力）とは何か。',c:['残留磁束密度 $B_r$ から $H$ を変化させたとき $B=0$ になる $H$ の大きさ','磁化が最初に飽和する磁束密度','最大磁束密度','$B=H$ となる点'],a:0,exp:'保磁力 $H_c$：残留磁束密度 $B_r$ の状態から磁束密度をゼロにするために必要な逆方向磁場。永久磁石は高保磁力が必要。変圧器鉄心は低保磁力（ヒステリシス損小）が必要。'},
{id:'t188',s:'theory',cat:'電磁気',dif:2,q:'電界 $E$ と電束密度 $D$ の関係式はどれか。（$\\varepsilon$：誘電率）',c:['$D=E/\\varepsilon$','$D=\\varepsilon E$','$D=\\varepsilon/E$','$E=\\varepsilon^2 D$'],a:1,exp:'$D=\\varepsilon E=\\varepsilon_0\\varepsilon_r E$。$D$ は自由電荷に起因する電束密度で境界条件の計算に使う。ガウスの法則 $\\nabla\\cdot D=\\rho_v$。'},
{id:'t189',s:'theory',cat:'電磁気',dif:3,q:'マクスウェルの方程式の1つで電磁誘導を表すのはどれか。',c:['$\\nabla\\cdot\\boldsymbol{D}=\\rho_v$','$\\nabla\\times\\boldsymbol{E}=-\\partial\\boldsymbol{B}/\\partial t$','$\\nabla\\cdot\\boldsymbol{B}=0$','$\\nabla\\times\\boldsymbol{H}=\\boldsymbol{J}+\\partial\\boldsymbol{D}/\\partial t$'],a:1,exp:'$\\nabla\\times\\boldsymbol{E}=-\\partial\\boldsymbol{B}/\\partial t$：ファラデーの電磁誘導法則の微分形。変化する磁場が電界を生成することを表す。4つのマクスウェル方程式は電磁気学の全てを記述する。'},
{id:'t190',s:'theory',cat:'電磁気',dif:2,q:'平行平板コンデンサ（面積 $A$、間隔 $d$、電圧 $V$）に蓄えられるエネルギー密度はどれか。（$\\varepsilon$：誘電率）',c:['$u=\\varepsilon E^2/2$','$u=\\varepsilon E^2$','$u=E^2/(2\\varepsilon)$','$u=CV^2$'],a:0,exp:'静電エネルギー密度 $u=\\varepsilon E^2/2=D E/2=D^2/(2\\varepsilon)$（単位：J/m³）。全エネルギー $W=uAd=\\varepsilon E^2 Ad/2=CV^2/2$。'},
{id:'t191',s:'theory',cat:'電磁気',dif:2,q:'磁界のエネルギー密度はどれか。（$\\mu$：透磁率、$B$：磁束密度、$H$：磁界）',c:['$u=\\mu H^2$','$u=BH/2$','$u=B^2/(2\\mu)$','上記②と③は等しい（$B=\\mu H$ を代入すると同じ）'],a:3,exp:'磁界エネルギー密度 $u=BH/2=\\mu H^2/2=B^2/(2\\mu)$（単位：J/m³）。②と③は $B=\\mu H$ を代入すると同値。インダクタンスの蓄積エネルギー $W=LI^2/2$ に対応。'},
{id:'t192',s:'theory',cat:'電磁気',dif:2,q:'平行平板コンデンサの両極板間に引力が働く。この引力 $F$ はどれか。（電荷量 $Q$、面積 $A$）',c:['$F=Q^2/(2\\varepsilon A)$','$F=Q^2/(\\varepsilon A)$','$F=\\varepsilon A/Q$','$F=Q/(2\\varepsilon A)$'],a:0,exp:'極板間の引力 $F=Q^2/(2\\varepsilon_0 A)=\\varepsilon_0 E^2 A/2$。これは静電圧力（Maxwell応力）と呼ばれ、電気機器の絶縁設計で考慮する。'},
{id:'t193',s:'theory',cat:'電磁気',dif:2,q:'フレミングの右手の法則は何を決めるのに使うか。',c:['電動機の力の方向','発電機の誘起起電力の方向','磁場の向き','電流の向き'],a:1,exp:'フレミングの右手の法則（発電機則）：親指＝導体運動方向、人差し指＝磁場方向、中指＝誘起電流（起電力）方向。フレミングの左手の法則は電動機（力の方向）。'},
{id:'t194',s:'theory',cat:'電磁気',dif:2,q:'電磁誘導によって誘起される起電力の方向を示す法則はどれか。',c:['アンペールの法則','フレミングの左手の法則','レンツの法則','ビオ・サバールの法則'],a:2,exp:'レンツの法則：誘起起電力は磁束変化を妨げる方向に誘起される（$e=-d\\Phi/dt$ の負号）。エネルギー保存則と整合する自然の法則。'},
{id:'t195',s:'theory',cat:'電磁気',dif:2,q:'磁束密度 $B=1\\,\\text{T}$、長さ $\\ell=0.5\\,\\text{m}$ の導体が速度 $v=10\\,\\text{m/s}$ で磁場に直交して動くとき誘起起電力はいくらか。',c:['$0.05\\,\\text{V}$','$0.5\\,\\text{V}$','$5\\,\\text{V}$','$50\\,\\text{V}$'],a:2,exp:'$e=Bv\\ell=1\\times10\\times0.5=5\\,\\text{V}$（フレミングの右手）。これが発電機・電動機の逆起電力の基本式。$e=Bv\\ell\\sin\\theta$（一般角）。'},
{id:'t196',s:'theory',cat:'電磁気',dif:2,q:'円形コイル（半径 $r$、巻数 $N$、電流 $I$）の中心の磁界 $H$ はどれか。',c:['$H=NI/(2r)$','$H=NI/r$','$H=NI/(4\\pi r)$','$H=2NI/r$'],a:0,exp:'円形コイル中心の磁界：$H=NI/(2r)$。ビオ・サバールの法則を積分して求める。磁束密度 $B=\\mu_0 NI/(2r)$。'},
{id:'t197',s:'theory',cat:'電磁気',dif:2,q:'永久磁石に適した材料の特性はどれか。',c:['高透磁率・低保磁力','低透磁率・高保磁力・高残留磁束密度','高透磁率・高保磁力','低残留磁束密度・低保磁力'],a:1,exp:'永久磁石：高保磁力 $H_c$（容易に消磁されない）・高残留磁束密度 $B_r$（強い磁場）が必要。変圧器鉄心は逆に低保磁力・高透磁率が必要。'},
{id:'t198',s:'theory',cat:'電磁気',dif:3,q:'電気双極子モーメント $\\boldsymbol{p}$ の定義はどれか。（電荷 $+q$ と $-q$ が距離 $d$ 離れている）',c:['$p=qd^2$','$p=qd$（$-q$ から $+q$ へ向くベクトル）','$p=q/d$','$p=2qd$'],a:1,exp:'電気双極子モーメント $p=qd$（大きさ、方向は $-q$→$+q$）。分極した誘電体は微小双極子の集まりとして扱う。双極子からの遠距離電場は $1/r^3$ で減衰。'},
{id:'t199',s:'theory',cat:'電磁気',dif:2,q:'ガウスの法則（電界版）の積分形はどれか。',c:['$\\oint\\boldsymbol{E}\\cdot d\\boldsymbol{\\ell}=0$','$\\oint\\boldsymbol{E}\\cdot d\\boldsymbol{A}=Q_{enc}/\\varepsilon_0$','$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{A}=0$','$\\oint\\boldsymbol{H}\\cdot d\\boldsymbol{\\ell}=I$'],a:1,exp:'ガウスの法則：閉曲面を通る電束＝内部の全電荷/$\\varepsilon_0$。球対称・柱対称など対称性のある電荷分布の電界計算に有効。'},
{id:'t200',s:'theory',cat:'電磁気',dif:2,q:'磁場に関するガウスの法則（磁束の法則）はどれか。',c:['$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{A}=\\mu_0 I$','$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{A}=0$','$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{\\ell}=I$','$\\nabla\\cdot\\boldsymbol{B}=\\rho_m$'],a:1,exp:'$\\oint\\boldsymbol{B}\\cdot d\\boldsymbol{A}=0$：磁気単極子（モノポール）は存在しないため、磁束線は閉じた曲線を描く（湧き出し・吸い込みなし）。'},
{id:'t201',s:'theory',cat:'電磁気',dif:3,q:'変位電流 $J_D$ の定義はどれか。（$D$：電束密度）',c:['$J_D=\\partial D/\\partial t$','$J_D=\\nabla\\times D$','$J_D=D/t$','$J_D=\\varepsilon\\nabla D$'],a:0,exp:'マクスウェルが導入した変位電流 $J_D=\\partial D/\\partial t=\\varepsilon\\partial E/\\partial t$。コンデンサの極板間など真の電流が流れない場所でも「電流」が連続することを保証し、電磁波の存在を予言した。'},
{id:'t202',s:'theory',cat:'電磁気',dif:2,q:'鉄心を有するソレノイドのインダクタンスは空心のときの何倍か。（比透磁率 $\\mu_r$）',c:['$1/\\mu_r$ 倍','$\\sqrt{\\mu_r}$ 倍','$\\mu_r$ 倍','$\\mu_r^2$ 倍'],a:2,exp:'$L=\\mu_0\\mu_r N^2 A/\\ell$。鉄心を入れると $\\mu_r$ 倍のインダクタンスが得られる（電磁石・変圧器・電動機の原理）。'},
{id:'t203',s:'theory',cat:'電磁気',dif:2,q:'自己インダクタンス $L=0.1\\,\\text{H}$ のコイルの電流が $dt=0.01\\,\\text{s}$ で $dI=5\\,\\text{A}$ 変化したとき誘起起電力はいくらか。',c:['$0.5\\,\\text{V}$','$5\\,\\text{V}$','$50\\,\\text{V}$','$500\\,\\text{V}$'],a:2,exp:'$e=-L\\,dI/dt=-0.1\\times5/0.01=-50\\,\\text{V}$（大きさ $50\\,\\text{V}$）。インダクタンスは電流変化を妨げる逆起電力を生成する。'},
{id:'t204',s:'theory',cat:'電磁気',dif:2,q:'電荷 $q$ が速度 $v$ で磁束密度 $B$ に垂直に運動するとき受ける力（磁力）の大きさはどれか。',c:['$F=qvB\\cos\\theta$','$F=qvB$（直交時）','$F=qB/v$','$F=q/vB$'],a:1,exp:'$F=qvB\\sin\\theta$。電荷が磁場に直交して動く場合（$\\theta=90°$）：$F=qvB$。この力は速度に垂直なため仕事をしない（運動エネルギーを変えない）。'},
{id:'t205',s:'theory',cat:'電磁気',dif:2,q:'平行導線に同方向の電流 $I_1$、$I_2$ が流れるとき2導線間の電磁力はどうなるか。',c:['反発力が働く','引力が働く','力が働かない','回転力が働く'],a:1,exp:'同方向電流：引力。逆方向電流：反発力。1アンペアの定義（旧SI）：真空中で1m離れた平行導線に $2\\times10^{-7}\\,\\text{N/m}$ の引力が働く電流。'},
{id:'t206',s:'theory',cat:'電磁気',dif:3,q:'ポインティングベクトル $\\boldsymbol{S}$ はどれか。（電磁波のエネルギー流束）',c:['$\\boldsymbol{S}=\\boldsymbol{E}\\cdot\\boldsymbol{H}$','$\\boldsymbol{S}=\\boldsymbol{E}\\times\\boldsymbol{H}$','$\\boldsymbol{S}=\\boldsymbol{E}+\\boldsymbol{H}$','$\\boldsymbol{S}=\\boldsymbol{E}/\\boldsymbol{H}$'],a:1,exp:'ポインティングベクトル $\\boldsymbol{S}=\\boldsymbol{E}\\times\\boldsymbol{H}$（W/m²）：電磁エネルギーの単位面積あたりのフラックス。電磁波の進行方向に電力が伝わる。'},
{id:'t207',s:'theory',cat:'電磁気',dif:2,q:'真空中の電磁波の速度はどれか。（$\\varepsilon_0$：真空誘電率、$\\mu_0$：真空透磁率）',c:['$c=\\sqrt{\\mu_0/\\varepsilon_0}$','$c=1/\\sqrt{\\mu_0\\varepsilon_0}$','$c=\\mu_0\\varepsilon_0$','$c=\\varepsilon_0/\\mu_0$'],a:1,exp:'電磁波速度（光速）$c=1/\\sqrt{\\mu_0\\varepsilon_0}\\approx3\\times10^8\\,\\text{m/s}$。誘電体中では $v=c/\\sqrt{\\varepsilon_r\\mu_r}$ となり遅くなる。'},
{id:'t208',s:'theory',cat:'電磁気',dif:2,q:'磁気双極子（双極子磁石）の磁気モーメント $m$ の単位はどれか。',c:['T（テスラ）','A/m','A·m²','Wb（ウェーバ）'],a:2,exp:'磁気モーメント $m$（単位：A·m²）＝電流 $I$×ループ面積 $A$。永久磁石や電子スピンも磁気モーメントで表せる。'},
{id:'t209',s:'theory',cat:'電磁気',dif:2,q:'誘電体の分極の種類として誤っているのはどれか。',c:['電子分極','イオン分極','配向分極','磁気分極'],a:3,exp:'誘電分極の種類：①電子分極（電子雲のひずみ）②イオン分極（イオンの変位）③配向分極（双極子の整列）。磁気分極は磁性体の話で誘電体の分極ではない。'},
{id:'t210',s:'theory',cat:'電磁気',dif:2,q:'強磁性体の特徴として正しいのはどれか。',c:['比透磁率が1よりわずかに大きい（常磁性体と同程度）','キュリー温度以上で強磁性を失い常磁性になる','磁化が外部磁場に反比例する','常温で磁化されない'],a:1,exp:'強磁性体（Fe、Ni、Co等）：比透磁率が数百〜数万と非常に高い。キュリー温度（Feは770°C）以上で磁区が消え常磁性体になる。ヒステリシスを示す。'},
{id:'t211',s:'theory',cat:'電磁気',dif:3,q:'電界 $E=10^6\\,\\text{V/m}$ の点における静電気圧力（単位面積あたりの力）はどれか。（$\\varepsilon_0=8.85\\times10^{-12}\\,\\text{F/m}$）',c:['$4.4\\,\\text{Pa}$','$8.85\\,\\text{Pa}$','$44.2\\,\\text{Pa}$','$4420\\,\\text{Pa}$'],a:0,exp:'静電圧力 $P_e=\\varepsilon_0 E^2/2=8.85\\times10^{-12}\\times(10^6)^2/2=4.4\\,\\text{Pa}$。マクスウェル応力テンソルの垂直成分。'},
{id:'t212',s:'theory',cat:'電磁気',dif:2,q:'同軸ケーブルの内導体（半径 $a$）と外導体（内半径 $b$）の間の静電容量 $C$（単位長さ当たり）はどれか。',c:['$C=2\\pi\\varepsilon/\\ln(b/a)$','$C=\\pi\\varepsilon/\\ln(a/b)$','$C=2\\pi\\varepsilon\\ln(b/a)$','$C=\\varepsilon/\\ln(b/a)$'],a:0,exp:'同軸ケーブルの静電容量：$C=2\\pi\\varepsilon/\\ln(b/a)$（F/m）。対数比で表されるため、内外径の比が小さいほど容量が大きい。'},
{id:'t213',s:'theory',cat:'電磁気',dif:2,q:'電気双極子から距離 $r$ の点における電界の強さはどの関係で減衰するか。',c:['$1/r$','$1/r^2$','$1/r^3$','$1/r^4$'],a:2,exp:'電気双極子の遠距離電場 $E\\propto1/r^3$（単独の点電荷は $1/r^2$）。磁気双極子も同様に $B\\propto1/r^3$。より遠くで急速に減衰する。'},
{id:'t214',s:'theory',cat:'電磁気',dif:2,q:'鉄心入りトロイダルコイル（断面積 $A$、平均磁路長 $\\ell$、巻数 $N$、比透磁率 $\\mu_r$）のインダクタンスはどれか。',c:['$L=\\mu_0\\mu_r N A/\\ell$','$L=\\mu_0\\mu_r N^2 A/\\ell$','$L=\\mu_0 N^2/(\\mu_r A\\ell)$','$L=\\mu_r N^2\\ell/A$'],a:1,exp:'$L=\\mu_0\\mu_r N^2 A/\\ell$。巻数の2乗に比例し、磁路長に反比例する。エアギャップを設けると実効透磁率が低下しインダクタンスが減少するが直流重畳特性が改善する。'},
{id:'t215',s:'theory',cat:'電磁気',dif:3,q:'電磁遮蔽（シールド）に金属板を使う場合、低周波では何の効果で遮蔽するか。',c:['表皮効果（渦電流）','誘導電流による反磁界','透磁率が高いため磁束を迂回させる','電気抵抗が低いため電界を遮断'],a:2,exp:'低周波磁気シールド：高透磁率材料（パーマロイ等）で磁束を迂回させる。高周波では渦電流による反磁界効果（銅・アルミ等）。電界シールドは金属箱（ファラデーゲージ）。'},
{id:'t216',s:'theory',cat:'電磁気',dif:2,q:'誘電体の比誘電率 $\\varepsilon_r$ の物理的意味はどれか。',c:['同じ容量を実現するのに必要な面積の比','真空コンデンサに比べて何倍の容量になるか','誘電損失の大きさ','絶縁破壊電圧の逆数'],a:1,exp:'比誘電率 $\\varepsilon_r$：誘電体を入れることで静電容量が真空（空気）の何倍になるかを示す無次元数。水 $\\varepsilon_r\\approx80$、マイカ $\\approx7$、ポリエチレン $\\approx2.3$。'},
{id:'t217',s:'theory',cat:'電磁気',dif:2,q:'磁気回路において鉄心にエアギャップを設けるとインダクタンスはどうなるか。',c:['増加する','減少する','変化しない','鉄心の透磁率によって変わる'],a:1,exp:'エアギャップ（空気の $\\mu_r\\approx1$）は磁気抵抗が大きいため、磁気回路全体の磁気抵抗が増加→磁束が減少→インダクタンス減少。ただし直流重畳特性（磁気飽和しにくさ）は改善される。'},
{id:'t218',s:'theory',cat:'電磁気',dif:2,q:'コンデンサの誘電損失（誘電体損）を表す指標として使われるのはどれか。',c:['比誘電率 $\\varepsilon_r$','損失角の正接（誘電正接）$\\tan\\delta$','絶縁破壊電圧','静電容量 $C$'],a:1,exp:'誘電正接 $\\tan\\delta=\\varepsilon^{\\prime\\prime}/\\varepsilon^{\\prime}$（$\\varepsilon=\\varepsilon^{\\prime}-j\\varepsilon^{\\prime\\prime}$）。$\\tan\\delta$ が小さいほど誘電損失が少ない。高周波用コンデンサでは特に重要。'},
{id:'t219',s:'theory',cat:'電磁気',dif:3,q:'電流ループ（面積 $A$、電流 $I$）の磁気モーメント $m$ と等価な磁石の磁極強さ $p_m$ と長さ $\\ell$ の関係はどれか。',c:['$m=p_m/\\ell$','$m=p_m\\ell$','$m=p_m/\\ell^2$','$m=\\ell/p_m$'],a:1,exp:'磁気モーメント $m=p_m\\ell=IA$（単位：A·m²）。電流ループと磁気双極子は等価な遠距離磁場を生成する。電子の軌道磁気モーメントや核磁気共鳴（NMR）の基礎。'},
{id:'t220',s:'theory',cat:'電磁気',dif:2,q:'超電導体の磁気的特性として正しいのはどれか。（マイスナー効果）',c:['比透磁率が非常に大きくなる','内部の磁束密度がゼロになる（完全反磁性）','電気抵抗はゼロだが磁場は透過する','磁場によって抵抗がゼロになる'],a:1,exp:'マイスナー効果：超電導状態では内部磁束が完全に排除される（$B=0$）。完全反磁性。磁石の上に超電導体が浮く磁気浮上はこの効果による。'},
{id:'t221',s:'theory',cat:'電磁気',dif:2,q:'コンデンサ $C_1=2\\,\\mu\\text{F}$（電圧 $100\\,\\text{V}$）と $C_2=4\\,\\mu\\text{F}$（電圧 $50\\,\\text{V}$）を並列接続した後の電圧はいくらか。',c:['$50\\,\\text{V}$','$66.7\\,\\text{V}$','$75\\,\\text{V}$','$100\\,\\text{V}$'],a:1,exp:'全電荷 $Q=C_1V_1+C_2V_2=200+200=400\\,\\mu\\text{C}$。並列後 $C=6\\,\\mu\\text{F}$。$V=400/6\\approx66.7\\,\\text{V}$。電荷が保存される。'},
{id:'t222',s:'theory',cat:'電磁気',dif:2,q:'誘電体の境界面での電気的境界条件として正しいのはどれか。（法線成分）',c:['電束密度の法線成分は不連続','電界の法線成分は連続','電束密度の法線成分は面電荷がなければ連続（$D_{1n}=D_{2n}$）','電界の法線成分は常に連続'],a:2,exp:'境界条件：法線方向 $D_{1n}=D_{2n}$（面電荷なし）、接線方向 $E_{1t}=E_{2t}$（電界の接線成分は連続）。磁気境界：法線 $B_{1n}=B_{2n}$、接線 $H_{1t}=H_{2t}$（面電流なし）。'},
{id:'t223',s:'theory',cat:'電磁気',dif:3,q:'電磁誘導による渦電流損を低減するための変圧器鉄心の対策はどれか。',c:['厚い鉄板を使用する','鉄心を薄い珪素鋼板に積層して使用する','純鉄を使用する','鉄心を並列接続にする'],a:1,exp:'積層鉄心：薄い絶縁した珪素鋼板（一般に $0.3\\sim0.5\\,\\text{mm}$）を積層→渦電流損 $\\propto t^2$ を低減。珪素（Si）を添加することでヒステリシス損も低減。'},
{id:'t224',s:'theory',cat:'電磁気',dif:2,q:'磁気飽和の説明として正しいのはどれか。',c:['磁束密度が無限に増加できる状態','外部磁場を強くしても磁束密度の増加が鈍くなり最大値に近づく現象','磁気抵抗がゼロになる状態','磁石が完全に消磁された状態'],a:1,exp:'磁気飽和：強磁性体の磁区がすべて同じ方向に揃い、$H$ を増しても $B$ がほとんど増えない状態。変圧器の設計では飽和を避けるため磁束密度は $1.5\\sim1.7\\,\\text{T}$ 程度に設定。'},
{id:'t225',s:'theory',cat:'電磁気',dif:2,q:'コンデンサの絶縁破壊電圧を高くする方法として正しいのはどれか。',c:['誘電体を薄くする','比誘電率の高い誘電体を使う','誘電体の厚さを増す','電極面積を小さくする'],a:2,exp:'絶縁破壊電圧 $V_{br}=E_{br}\\times d$（$E_{br}$：絶縁破壊電界強度、$d$：誘電体厚さ）。厚さを増すと耐電圧が上がる（ただし静電容量は低下）。'},
{id:'t226',s:'theory',cat:'電磁気',dif:3,q:'磁気遮蔽（磁気シールド）に高透磁率材料を使う原理はどれか。',c:['磁束が高透磁率材料を避けて通る','磁束が高透磁率材料の内部を通りやすいため外部の磁束が迂回する','渦電流で磁束を打ち消す','電流を誘起して磁場を相殺する'],a:1,exp:'高透磁率材料（パーマロイ等）は磁束を集め内部に導く→保護したい空間（材料の内側）への磁束が減少。低周波磁場のシールドに有効。高周波は渦電流シールドが有効。'},
{id:'t227',s:'theory',cat:'電磁気',dif:2,q:'1巻コイルの断面積 $A=0.01\\,\\text{m}^2$ に鎖交する磁束密度が $dB/dt=100\\,\\text{T/s}$ で変化するとき誘起起電力はいくらか。',c:['$0.01\\,\\text{V}$','$0.1\\,\\text{V}$','$1\\,\\text{V}$','$10\\,\\text{V}$'],a:2,exp:'$e=N\\cdot A\\cdot dB/dt=1\\times0.01\\times100=1\\,\\text{V}$（大きさ）。$N=100$ 巻なら $e=100\\,\\text{V}$。変圧器の起電力はこの原理。'},

// ===== 電子回路 (30問) =====
{id:'t049',s:'theory',cat:'電子回路',dif:1,q:'pn 接合ダイオードに順方向電圧を加えたときの特性はどれか。',c:['電流はほとんど流れない','電流が指数関数的に増加する','電流が直線的に増加する','電流は一定値に制限される'],a:1,exp:'順バイアス：$I=I_0(e^{qV/kT}-1)$（ショックレー方程式）。Siダイオードは約 $0.6\\sim0.7\\,\\text{V}$ 以上で急増。GaAsは約 $1.2\\,\\text{V}$。'},
{id:'t050',s:'theory',cat:'電子回路',dif:2,q:'ツェナーダイオードの主な用途はどれか。',c:['整流','定電圧回路（電圧レギュレータ）','発振','増幅'],a:1,exp:'ツェナーダイオード：逆方向にツェナー電圧（降伏電圧）以上の電圧がかかると一定電圧を保持（降伏は破壊でなく可逆）。定電圧電源・基準電圧に使用。'},
{id:'t051',s:'theory',cat:'電子回路',dif:2,q:'トランジスタ（BJT）の電流増幅率 $h_{FE}=200$ のとき、$I_B=0.02\\,\\text{mA}$ のコレクタ電流 $I_C$ はいくらか。',c:['$0.1\\,\\text{mA}$','$1\\,\\text{mA}$','$4\\,\\text{mA}$','$10\\,\\text{mA}$'],a:2,exp:'$I_C=h_{FE}\\times I_B=200\\times0.02=4\\,\\text{mA}$。$I_E=I_C+I_B=4.02\\,\\text{mA}$。$h_{FE}=\\beta$ は直流電流増幅率。'},
{id:'t052',s:'theory',cat:'電子回路',dif:2,q:'反転増幅回路（オペアンプ）で $R_1=5\\,\\text{k}\\Omega$、$R_f=50\\,\\text{k}\\Omega$ のとき電圧利得（絶対値）はいくらか。',c:['$0.1$','$5$','$10$','$50$'],a:2,exp:'反転増幅：$|A_v|=R_f/R_1=50/5=10$。出力は入力と逆位相（$180°$）。入力インピーダンス $=R_1$。'},
{id:'t053',s:'theory',cat:'電子回路',dif:2,q:'非反転増幅回路（オペアンプ）で $R_1=10\\,\\text{k}\\Omega$、$R_f=40\\,\\text{k}\\Omega$ のとき電圧利得はいくらか。',c:['$1$','$4$','$5$','$40$'],a:2,exp:'非反転増幅：$A_v=1+R_f/R_1=1+40/10=5$。出力は入力と同位相。入力インピーダンスが非常に高い（バッファ特性）。'},
{id:'t054',s:'theory',cat:'電子回路',dif:2,q:'MOSFET の特徴として正しいのはどれか。',c:['電流制御型デバイスである','ゲート入力インピーダンスが非常に低い','電圧制御型デバイスでゲート電流はほぼゼロ','BJT より駆動電流が大きく必要'],a:2,exp:'MOSFET は電圧制御型。ゲートは酸化膜（SiO₂）で絶縁されているためゲート電流はほぼゼロ。高入力インピーダンス・低駆動電力。パワーエレクトロニクス・LSIに広く使用。'},
{id:'t055',s:'theory',cat:'電子回路',dif:2,q:'単相全波整流回路（ブリッジ）の直流平均電圧 $V_{av}$ はどれか。（$V_m$：最大値）',c:['$V_{av}=V_m/\\pi$','$V_{av}=2V_m/\\pi$','$V_{av}=V_m/2$','$V_{av}=\\sqrt{2}V_m/\\pi$'],a:1,exp:'単相全波整流：$V_{av}=2V_m/\\pi\\approx0.637V_m$。実効値 $V_{rms}=V_m/\\sqrt{2}$ より $V_{av}\\approx0.9V_{rms}$（変圧器の設計に必要）。'},
{id:'t228',s:'theory',cat:'電子回路',dif:2,q:'接合型FET（JFET）の特徴として正しいのはどれか。',c:['電流制御型デバイス','逆バイアスのゲート接合の空乏層でチャネルを制御する電圧制御型','ゲート電流が大きい','BJTと同様の動作原理'],a:1,exp:'JFET：ゲートとチャネル間の逆バイアスpn接合の空乏層幅を変えてチャネル抵抗を制御する。電圧制御型だが、MOSFETほど入力インピーダンスは高くない（ゲートに若干電流が流れる）。'},
{id:'t229',s:'theory',cat:'電子回路',dif:2,q:'演算増幅器の「仮想短絡（イマジナリーショート）」の意味はどれか。',c:['入力端子が実際に接続されている','フィードバックにより非反転・反転入力端子の電位差がほぼゼロになる','出力インピーダンスがゼロ','電源電圧がゼロ'],a:1,exp:'仮想短絡（バーチャルショート）：負フィードバックにより $V_+=V_-$（入力電圧差≒0）。電流は流れない点に注意（高入力インピーダンス）。オペアンプ回路解析の基礎。'},
{id:'t230',s:'theory',cat:'電子回路',dif:2,q:'オペアンプを用いた加算回路（反転加算器）で2入力 $V_1=1\\,\\text{V}$、$V_2=2\\,\\text{V}$、各入力抵抗 $R=10\\,\\text{k}\\Omega$、帰還抵抗 $R_f=10\\,\\text{k}\\Omega$ のとき出力 $V_o$ はいくらか。',c:['$-1\\,\\text{V}$','$-3\\,\\text{V}$','$+3\\,\\text{V}$','$-6\\,\\text{V}$'],a:1,exp:'反転加算：$V_o=-(R_f/R)(V_1+V_2)=-(1)(1+2)=-3\\,\\text{V}$。各入力の重みは $R_f/R_i$ で設定できる。'},
{id:'t231',s:'theory',cat:'電子回路',dif:2,q:'コンパレータ（比較器）の用途として正しいのはどれか。',c:['信号を増幅する','2つの電圧を比較して大小に応じてデジタル出力（High/Low）を得る','周波数を変換する','電力を変換する'],a:1,exp:'コンパレータ：$V_+>V_-$ なら出力High、$V_+<V_-$ なら出力Low。A/D変換・ゼロクロス検出・過電圧保護回路などに使用。負帰還がないためオープンループで動作。'},
{id:'t232',s:'theory',cat:'電子回路',dif:2,q:'npn トランジスタを飽和領域で動作させた場合の特徴はどれか。',c:['$I_C=\\beta I_B$（線形増幅）','コレクタ-エミッタ間電圧 $V_{CE}\\approx0.2\\sim0.3\\,\\text{V}$（スイッチON状態）','電流が遮断される','線形的に増幅できる'],a:1,exp:'飽和領域：$V_{CE}\\approx V_{CE(sat)}\\approx0.2\\,\\text{V}$（npn Siトランジスタ）。スイッチのON状態。デジタル回路・スイッチング電源に使用。遮断領域は電流がほぼゼロ（スイッチOFF）。'},
{id:'t233',s:'theory',cat:'電子回路',dif:2,q:'LC 発振回路（コルピッツ発振、ハートレー発振等）の発振周波数はどれか。',c:['$f=2\\pi\\sqrt{LC}$','$f=1/(2\\pi\\sqrt{LC})$','$f=\\sqrt{LC}/(2\\pi)$','$f=2\\pi/(\\sqrt{LC})$'],a:1,exp:'LC発振の共振周波数：$f=1/(2\\pi\\sqrt{LC})$。コルピッツ：コンデンサ分割でフィードバック。ハートレー：コイル分割でフィードバック。'},
{id:'t234',s:'theory',cat:'電子回路',dif:2,q:'半波整流回路の脈動率（ripple factor）は全波整流に比べてどうなるか。',c:['小さい','同じ','大きい','整流方式に依存しない'],a:2,exp:'脈動率（ripple factor）：半波整流 $\\approx1.21$、全波整流 $\\approx0.48$。半波は脈動が大きく平滑が困難。全波（ブリッジ）は2倍の周波数で脈動が半分以下になる。'},
{id:'t235',s:'theory',cat:'電子回路',dif:3,q:'シュミットトリガー回路の特徴はどれか。',c:['線形増幅を行う','ヒステリシス特性により入力ノイズを除去して安定したデジタル出力を得る','発振回路として使用する','整流回路として使用する'],a:1,exp:'シュミットトリガー：正帰還によりヒステリシス特性を持つ。上閾値（$V_{H}$）と下閾値（$V_{L}$）があり、ノイズが乗った波形を確実にデジタル信号に変換できる（チャタリング除去）。'},
{id:'t236',s:'theory',cat:'電子回路',dif:2,q:'電界効果トランジスタ（FET）の3端子の名称として正しいのはどれか。',c:['ベース・コレクタ・エミッタ','ゲート・ドレイン・ソース','アノード・カソード・ゲート','プレート・グリッド・カソード'],a:1,exp:'FET（JFET・MOSFET）：ゲート（G）・ドレイン（D）・ソース（S）。BJTのベース・コレクタ・エミッタに対応。ゲート電圧でドレイン電流を制御する。'},
{id:'t237',s:'theory',cat:'電子回路',dif:2,q:'理想オペアンプの特性として正しいのはどれか。',c:['入力インピーダンス=0、出力インピーダンス=∞、利得=1','入力インピーダンス=∞、出力インピーダンス=0、利得=∞','入力インピーダンス=∞、出力インピーダンス=∞、利得=∞','入力インピーダンス=0、出力インピーダンス=0、利得=0'],a:1,exp:'理想オペアンプ：入力インピーダンス無限大（ゲート電流ゼロ）、出力インピーダンスゼロ（電流供給能力無限大）、開ループ電圧利得無限大、帯域幅無限大。'},
{id:'t238',s:'theory',cat:'電子回路',dif:2,q:'PN ダイオードの逆回復時間（reverse recovery time）の説明として正しいのはどれか。',c:['順方向電圧が立ち上がる時間','逆バイアス印加後、少数キャリアが消滅して逆電流がゼロになるまでの時間','整流後の電圧が安定する時間','ピーク逆電圧（PIV）が印加される時間'],a:1,exp:'逆回復時間：順バイアスで注入された少数キャリアが逆バイアス印加後に消滅するまでの時間。高速スイッチング用にはショットキーダイオード（少数キャリア注入なし）が適する。'},
{id:'t239',s:'theory',cat:'電子回路',dif:2,q:'BJT（npn）のコモンエミッタ（CE）接続の電流利得 $\beta$ と $\\alpha$（コモンベース）の関係はどれか。',c:['$\\beta=\\alpha/(1-\\alpha)$','$\\beta=1-\\alpha$','$\\beta=\\alpha/(1+\\alpha)$','$\\beta=(1-\\alpha)/\\alpha$'],a:0,exp:'$\\beta=\\alpha/(1-\\alpha)$、$\\alpha=\\beta/(1+\\beta)$。$\\alpha\\to1$ のとき $\\beta\\to\\infty$。実用トランジスタは $\\alpha\\approx0.99$、$\\beta\\approx100$。'},
{id:'t240',s:'theory',cat:'電子回路',dif:3,q:'差動増幅器（差動対）の同相除去比（CMRR）の定義はどれか。',c:['差動利得/同相利得','同相利得/差動利得','差動利得 × 同相利得','差動利得 + 同相利得'],a:0,exp:'CMRR（Common Mode Rejection Ratio）＝差動利得 $A_d$ / 同相利得 $A_c$（dB で表すことも多い）。CMRRが大きいほど同相ノイズを除去できる（ECGなど生体信号計測に重要）。'},
{id:'t241',s:'theory',cat:'電子回路',dif:2,q:'整流回路の出力に設けるスムージング（平滑）コンデンサの役割はどれか。',c:['整流効率を高める','出力電圧の脈動（リプル）を低減する','逆電流を防止する','電圧を昇圧する'],a:1,exp:'平滑コンデンサ：整流後の脈流を充放電で平滑化し直流に近づける。容量が大きいほどリプルが小さくなるが、突入電流が大きくなる。時定数 $\\tau=RC$（$R$：負荷抵抗）が放電に影響。'},
{id:'t242',s:'theory',cat:'電子回路',dif:2,q:'555タイマーICの非安定マルチバイブレータ（発振）モードの周波数はどれか。（$R_A$、$R_B$：抵抗、$C$：コンデンサ）',c:['$f=1/(2.2(R_A+R_B)C)$','$f=1.44/((R_A+2R_B)C)$','$f=0.693(R_A+R_B)C$','$f=1/(R_A R_B C)$'],a:1,exp:'555タイマー（非安定）：$f\\approx1.44/((R_A+2R_B)C)$。デューティ比 $D=(R_A+R_B)/(R_A+2R_B)$。方形波発振器として多用される。'},
{id:'t243',s:'theory',cat:'電子回路',dif:3,q:'負帰還増幅回路の効果として誤っているのはどれか。',c:['利得の安定化','非線形ひずみの低減','入力インピーダンスの改善（直列帰還で増加）','利得が増加する'],a:3,exp:'負帰還の効果：①利得安定化 ②ひずみ・雑音の低減 ③入力/出力インピーダンス改善 ④帯域幅拡大。ただし利得は $(1+A\\beta)$ 倍減少するのが欠点（$A$：開ループ利得、$\\beta$：帰還率）。'},
{id:'t244',s:'theory',cat:'電子回路',dif:2,q:'トランジスタのアーリー効果（Early effect）の説明として正しいのはどれか。',c:['温度が上がると電流増幅率が低下する現象','コレクタ-エミッタ電圧の増加によりコレクタ電流が緩やかに増加する現象','ベース電流がゼロになると電流が流れなくなる現象','高周波で電流利得が低下する現象'],a:1,exp:'アーリー効果：$V_{CE}$ 増加→空乏層幅増加→実効ベース幅減少→$\\beta$ 増加→$I_C$ が緩やかに増加。アーリー電圧 $V_A$ で表され、理想的なトランジスタでは無限大。'},
{id:'t245',s:'theory',cat:'電子回路',dif:2,q:'ダーリントン接続（Darlington pair）の特徴はどれか。',c:['電流増幅率が $\\beta_1+\\beta_2$','電流増幅率が $\\beta_1\\times\\beta_2$（大幅な増幅）','電流増幅率が $\\beta_1-\\beta_2$','電流増幅率が変わらない'],a:1,exp:'ダーリントン接続：$\\beta_{total}\\approx\\beta_1\\times\\beta_2$（個別のβの積）。たとえば $\\beta_1=\\beta_2=100$ なら $\\beta_{total}\\approx10000$。大電流ドライブに使用（Hブリッジ、モータドライバなど）。'},
{id:'t246',s:'theory',cat:'電子回路',dif:2,q:'オペアンプを用いた微分回路（入力側にC、帰還側にR）の出力はどれか。',c:['入力を積分した波形','入力を微分した波形（位相が $90°$ 進む）','入力と同じ波形（増幅のみ）','定電流出力'],a:1,exp:'微分回路：$V_o=-RC\\,dV_i/dt$。方形波入力に対してインパルス状出力。高周波ノイズを増幅する欠点があるため、実際は抵抗を直列に入れて高域を制限する。'},
{id:'t247',s:'theory',cat:'電子回路',dif:2,q:'オペアンプを用いた積分回路（入力側にR、帰還側にC）の出力はどれか。',c:['入力を微分した波形','入力を積分した波形（位相が $90°$ 遅れる）','入力と同じ波形','定電圧出力'],a:1,exp:'積分回路：$V_o=-\\frac{1}{RC}\\int V_i\\,dt$。方形波入力に対して三角波出力。直流オフセットが積分されて出力が飽和する問題があるため帰還コンデンサに並列抵抗を入れる場合がある。'},
{id:'t248',s:'theory',cat:'電子回路',dif:3,q:'光電変換素子のうち、入射光量に比例した電流を出力するのはどれか。',c:['発光ダイオード（LED）','フォトダイオード','光電管（真空管）のみ','全て同じ'],a:1,exp:'フォトダイオード（photodiode）：逆バイアス状態で入射光により電子正孔対が生成→光電流（光量に比例）が流れる。太陽電池もpn接合を利用した光電変換素子（フォトボルタイック動作）。'},
{id:'t249',s:'theory',cat:'電子回路',dif:2,q:'絶縁ゲートバイポーラトランジスタ（IGBT）の特徴として正しいのはどれか。',c:['MOSFETの電圧制御性とバイポーラトランジスタの低飽和電圧特性を組み合わせた素子','電流制御型で大電流に不向き','ゲート電流が大きい','直流のみ制御できる'],a:0,exp:'IGBT：MOSゲートで電圧制御（低ドライブ電力）＋バイポーラ動作で高電流・低 $V_{CE(sat)}$。インバータ・鉄道・自動車など高電圧・大電流スイッチングに広く使用。'},
{id:'t250',s:'theory',cat:'電子回路',dif:2,q:'デジタル回路でCMOS（相補型MOS）の消費電力の特徴はどれか。',c:['常に大きな電流が流れる','スイッチング時のみ電流が流れ、静止時の消費電力がほぼゼロ','TTLより消費電力が大きい','電源電圧の2乗に反比例する'],a:1,exp:'CMOS：pMOSとnMOSの相補構成。スイッチング遷移時のみ充放電電流が流れ、静的消費電力はほぼゼロ（$\\mu\\text{W}$ オーダー）。TTLに比べて低消費電力。動的消費電力は $P\\propto CV^2 f$。'},

]; // end Q_THEORY
